export enum Platform {
  SHOPEE = 'Shopee',
  LAZADA = 'Lazada',
  TIKTOK = 'TikTok',
  FACEBOOK = 'Facebook',
  WOOCOMMERCE = 'WooCommerce'
}

export type UserRole = 'owner' | 'employee' | 'collaborator';

export interface UserProfile {
  id: string;
  name: string;
  role: UserRole;
  avatar: string;
  assignedShopIds: string[];
  // Thêm các trường mới
  email?: string;
  phone?: string;
  emailVerified?: boolean;
  phoneVerified?: boolean;
}

export interface ProductVariant {
  id: string;
  name: string; // e.g. "Red - L"
  sku: string;
  price: number;
  stock: number;
  image?: string; // New field for variant image
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  price: number;
  salePrice?: number;
  importPrice?: number;
  currency: string;
  stock: number;
  minStock?: number;
  maxStock?: number;
  warehouseStocks: Record<string, number>;
  totalSold: number;
  platforms: Platform[];
  image: string;
  gallery: string[];
  video?: string;
  description: string;
  category: string;
  status: 'active' | 'draft' | 'out_of_stock';

  // Shipping info
  weight?: number; // grams
  length?: number; // cm
  width?: number; // cm
  height?: number; // cm

  // Variants
  variants?: ProductVariant[];
}

export interface OrderItem {
  productId: string;
  name: string;
  image: string;
  sku: string;
  variant: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  customerName: string;
  customerPhone?: string;
  address?: string;
  platform: Platform | 'Manual';
  shopId: string;
  date: string;
  shipByDate?: string;
  total: number;
  shippingFee: number;
  platformFee: number;
  tax: number;
  profit: number;
  status: 'pending' | 'processing' | 'shipping' | 'delivered' | 'cancelled' | 'returned';
  subStatus?: 'unprocessed' | 'printed' | 'packed';
  items: OrderItem[];
  shippingCarrier?: string;
  shippingMethod?: string;
  isCOD: boolean;
  trackingCode?: string;
  note?: string;
}

export interface IntegrationConfig {
  platform: Platform;
  shops: {
    id: string;
    name: string;
    logo: string;
    connectedAt: string;
    expiresAt: string;
    status: 'active' | 'expired';
  }[];
}

export interface ShippingProvider {
  id: string;
  name: string;
  logo: string;
  connected: boolean;
  type: 'domestic' | 'international';
}

export interface PlatformStat {
  platform: Platform;
  revenue: number;
  profit: number;
  productsCount: number;
  ordersCount: number;
  itemsSold: number;
  growth: number;
}

export interface ChartData {
  name: string;
  sales: number;
  orders: number;
}

export interface ChatMessage {
  id: string;
  text: string;
  sender: 'customer' | 'user';
  timestamp: string;
}

export interface Conversation {
  id: string;
  customerName: string;
  avatar: string;
  platform: Platform;
  lastMessage: string;
  timestamp: string;
  unreadCount: number;
  messages: ChatMessage[];
  sender: 'customer' | 'user';
}

export interface HourlySalesData {
  hour: string;
  today: number;
  yesterday: number;
}

export interface ReportDataPoint {
  label: string;
  revenue: number;
  profit: number;
  orders: number;
  itemsSold: number;
}

export interface TopSKU {
  rank: number;
  id: string;
  name: string;
  image: string;
  orders: number;
  revenue: number;
  stock: number;
