  value: number;
  color: string;
}

export interface TaxPayerProfile {
  name: string;
  taxCode: string;
  address: string;
  businessType: 'individual' | 'household' | 'company';
  taxAuthority: string;
  email: string;
  phone: string;
}

export interface TaxPayment {
  id: string;
  date: string;
  amount: number;
  quarter: number;
  year: number;
  status: 'paid' | 'pending';
  note: string;
}

export interface InputInvoice {
  id: string;
  date: string;
  invoiceNumber: string;
  sellerName: string;
  sellerTaxCode: string;
  description: string;
  totalAmount: number;
}

export interface TaxMessage {
  id: string;
  sender: 'user' | 'admin';
  content: string;
  type: 'text' | 'file';
  fileName?: string;
  timestamp: string;
}

export interface TaxTicket {
  id: string;
  subject: string;
  status: 'open' | 'processing' | 'closed';
  createdAt: string;
  updatedAt: string;
