}

export interface Invoice {
  id: string;
  type: 'input' | 'output'; // input: Mua vào, output: Bán ra
  invoiceNumber: string;
  date: string;
  partnerName: string; // Customer or Supplier
  partnerTaxCode?: string;
  totalAmount: number; // Tổng thanh toán
  preTaxAmount: number; // Trước thuế
  vatAmount: number; // Tiền thuế
  vatRate: number; // % Thuế (0, 5, 8, 10)
  items: string; // Summary of items
  status: 'paid' | 'unpaid' | 'cancelled';
  paymentMethod: 'cash' | 'transfer' | 'card';
  staffName: string;
  imageUrl?: string; // URL of the uploaded image/pdf (Primary)
  attachments?: string[]; // List of file URLs
  folder?: string; // e.g., "Tháng 5/2025"
  createdAt?: string; // Timestamp of entry
  creator?: string; // Account who entered
}

export interface LedgerRecord {
  id: string;
  date: string;
  type: 'receipt' | 'payment'; // Thu / Chi
  amount: number;
  description: string;
  category: string; // e.g., 'Doanh thu bán hàng', 'Nhập hàng', 'Chi phí vận hành', 'Lương nhân viên'
  method: 'cash' | 'bank';
  partnerName?: string;
  relatedDocId?: string; // Invoice ID or Order ID
  attachments?: string[]; // List of file URLs/Names
  createdAt?: string; // Timestamp of entry
}

export interface NewsArticle {
  id: string;
  title: string;
  summary: string;
  content: string;
  source: string;
  date: string;
  imageUrl: string;
  category: 'policy' | 'market' | 'tips' | 'tech';
}

