                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:bg-indigo-400"
                >
                    {isLoading ? 'Đang xử lý...' : 'Đổi mật khẩu'}
