const AppleIcon = () => (
  <svg className="w-5 h-5" viewBox="0 0 24 24" fill="currentColor" xmlns="http://www.w3.org/2000/svg">
    <path d="M17.05 20.28C15.77 22.09 14.28 22.07 12.86 22.07C11.39 22.07 10.95 21.24 9.25 21.24C7.54 21.24 7.02 22.04 5.68 22.07C4.31 22.09 2.19 19.72 1.05 18.06C-1.35 14.62 0.38 8.89 4.38 8.7C6.01 8.64 7.27 9.8 8.27 9.8C9.25 9.8 10.92 8.44 12.72 8.64C13.47 8.68 15.58 8.95 16.92 10.92C16.82 10.98 14.9 12.1 14.92 14.65C14.95 17.47 17.42 18.43 17.5 18.47C17.46 18.63 17.3 19.26 17.05 20.28ZM12.03 5.86C12.74 4.97 13.22 3.73 13.08 2.51C11.96 2.56 10.61 3.26 9.81 4.19C9.09 5.03 8.52 6.32 8.71 7.51C9.92 7.6 11.27 6.8 12.03 5.86Z"/>
  </svg>
);

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [view, setView] = useState<AuthView>('login');
  const [isLoading, setIsLoading] = useState(false);
  const [selectedRole, setSelectedRole] = useState<UserRole>('owner');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Input States
  const [loginEmail, setLoginEmail] = useState('');
  const [loginPassword, setLoginPassword] = useState('');

  const [registerName, setRegisterName] = useState('');
  const [registerEmail, setRegisterEmail] = useState('');
  const [registerPassword, setRegisterPassword] = useState('');
  const [isPasswordFocused, setIsPasswordFocused] = useState(false);

  // Forgot Password State
  const [forgotStep, setForgotStep] = useState<ForgotStep>('email');
  const [resetEmail, setResetEmail] = useState('');

  // OTP State
  const [otpCode, setOtpCode] = useState<string[]>(new Array(6).fill(""));
  const inputRefs = useRef<(HTMLInputElement | null)[]>([]);

  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Clear errors when switching views
  useEffect(() => {
    setError(null);
    setLoginEmail('');
    setLoginPassword('');
    setRegisterName('');
    setRegisterEmail('');
    setRegisterPassword('');
  }, [view]);

  // Password Strength Criteria
  const passwordCriteria = {
    length: registerPassword.length >= 8,
    hasLower: /[a-z]/.test(registerPassword),
    hasUpper: /[A-Z]/.test(registerPassword),
    hasNumber: /[0-9]/.test(registerPassword),
  };

  const isPasswordValid = Object.values(passwordCriteria).every(Boolean);

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // --- LOGIN LOGIC ---
    if (view === 'login') {
      if (!loginEmail || !loginPassword) {
        setError('Vui lòng nhập email và mật khẩu.');
        return;
      }

      if (!validateEmail(loginEmail)) {
        setError('Định dạng email không hợp lệ (ví dụ: user@example.com).');
        return;
      }

      // Simulate backend check against Mock Data
      const existingUser = MOCK_USERS.find(u => u.email === loginEmail);
      if (!existingUser) {
        setError('Email này chưa được đăng ký trong hệ thống.');
        return;
      }

      // Simulate password check (Mock: for demo, reject if password length < 6)
      if (loginPassword.length < 6) {
        setError('Mật khẩu không chính xác. Vui lòng thử lại.');
        return;
      }

      setIsLoading(true);
      setTimeout(() => {
        setIsLoading(false);
        // Use the found mock user or fallback based on role selector for demo purposes
        const mockUser = MOCK_USERS.find(u => u.role === selectedRole) || MOCK_USERS[0];
        onLogin(mockUser);
      }, 800);
    } 

    // --- REGISTER LOGIC ---
    else if (view === 'register') {
      if (!registerName || !registerEmail || !registerPassword) {
        setError('Vui lòng điền đầy đủ thông tin.');
        return;
      }

      if (!validateEmail(registerEmail)) {
        setError('Định dạng email không hợp lệ.');
        return;
      }

      // Check duplications
      const isDuplicate = MOCK_USERS.some(u => u.email === registerEmail);
      if (isDuplicate) {
        setError('Email này đã được sử dụng. Vui lòng đăng nhập hoặc dùng email khác.');
        return;
      }

      if (!isPasswordValid) {
        setError("Mật khẩu chưa đủ mạnh. Vui lòng kiểm tra lại yêu cầu bên dưới.");
        return;
      }

      setIsLoading(true);
      setTimeout(() => {
        setIsLoading(false);
        // Login as new user (mock)
        const newUser: UserProfile = {
            id: `u-${Date.now()}`,
            name: registerName,
            email: registerEmail,
            role: selectedRole,
            avatar: `https://ui-avatars.com/api/?name=${registerName}&background=random`,
            assignedShopIds: []
        };
        onLogin(newUser);
      }, 1000);
    }
  };

  const handleSocialLogin = (platform: 'Google' | 'Apple') => {
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      const mockUser = MOCK_USERS[0]; 
      onLogin(mockUser);
    }, 1000);
  };

  // --- Forgot Password Handlers ---

  const handleSendOtp = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if(!validateEmail(resetEmail)) {
        setError('Vui lòng nhập địa chỉ email hợp lệ.');
        return;
    }

    // Check if email exists
    const userExists = MOCK_USERS.find(u => u.email === resetEmail);
    if (!userExists) {
        setError('Email không tồn tại trong hệ thống.');
        return;
    }

    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      setForgotStep('otp');
    }, 1000);
  };

  const handleOtpChange = (element: HTMLInputElement, index: number) => {
    const val = element.value;
    if (isNaN(Number(val))) return; 

    const newOtp = [...otpCode];
    newOtp[index] = val.substring(val.length - 1); 
    setOtpCode(newOtp);

    if (val && index < 5) {
        inputRefs.current[index + 1]?.focus();
    }
  };

  const handleOtpKeyDown = (e: React.KeyboardEvent<HTMLInputElement>, index: number) => {
    if (e.key === "Backspace") {
        if (!otpCode[index] && index > 0) {
            inputRefs.current[index - 1]?.focus();
        }
    }
  };

  const handleOtpPaste = (e: React.ClipboardEvent<HTMLInputElement>) => {
    e.preventDefault();
    const pastedData = e.clipboardData.getData("text").replace(/[^0-9]/g, '').slice(0, 6).split("");
    const newOtp = [...otpCode];
    pastedData.forEach((val, i) => {
        if (i < 6) newOtp[i] = val;
    });
    setOtpCode(newOtp);
    const nextIndex = Math.min(pastedData.length, 5);
    inputRefs.current[nextIndex]?.focus();
  };

  const handleVerifyOtp = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const code = otpCode.join("");
    if(code.length !== 6) {
        setError("Vui lòng nhập đủ 6 số xác nhận");
        return;
    }
    // Mock OTP check
    if (code === '000000') {
        setError("Mã xác nhận không chính xác.");
        return;
    }

    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      setForgotStep('reset');
    }, 1000);
  };

  const handleResetPassword = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    if(newPassword.length < 6) {
        setError("Mật khẩu mới quá ngắn (tối thiểu 6 ký tự).");
        return;
    }
    if(newPassword !== confirmPassword) {
        setError("Mật khẩu xác nhận không khớp!");
        return;
    }
    setIsLoading(true);
    setTimeout(() => {
      setIsLoading(false);
      setForgotStep('success');
    }, 1000);
  };

  const resetForgotState = () => {
      setView('login');
      setForgotStep('email');
      setResetEmail('');
      setOtpCode(new Array(6).fill(""));
      setNewPassword('');
      setConfirmPassword('');
      setError(null);
  };

  const renderError = () => (
    error ? (
      <div className="bg-red-50 border border-red-100 text-red-600 px-4 py-3 rounded-lg text-sm flex items-center gap-2 animate-fade-in mb-4">
        <AlertTriangle size={18} className="shrink-0" />
        <span>{error}</span>
      </div>
    ) : null
  );

  const renderForgotPassword = () => (
    <div className="p-8">
      {forgotStep === 'email' && (
        <div className="animate-fade-in">
            <button 
                onClick={resetForgotState}
                className="flex items-center gap-1 text-slate-500 hover:text-indigo-600 text-sm mb-6 transition-colors"
            >
                <ChevronLeft size={16} /> Quay lại đăng nhập
            </button>

            <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center mb-4">
                <KeyRound size={24} />
            </div>

            <h2 className="text-2xl font-bold text-slate-800 mb-2">Quên mật khẩu?</h2>
            <p className="text-slate-500 text-sm mb-8">Nhập địa chỉ email của bạn và chúng tôi sẽ gửi mã xác nhận.</p>

            <form onSubmit={handleSendOtp} className="space-y-4">
                {renderError()}
                <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                    type="email" 
                    value={resetEmail}
                    onChange={(e) => { setResetEmail(e.target.value); setError(null); }}
                    placeholder="Email của bạn"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                    required
                    />
                </div>
                <button 
                    type="submit" 
                    disabled={isLoading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:bg-indigo-400"
                >
                    {isLoading ? 'Đang gửi...' : 'Gửi mã xác nhận'}
                </button>
            </form>
        </div>
      )}

      {forgotStep === 'otp' && (
        <div className="animate-fade-in">
            <button 
                onClick={() => setForgotStep('email')}
                className="flex items-center gap-1 text-slate-500 hover:text-indigo-600 text-sm mb-6 transition-colors"
            >
                <ChevronLeft size={16} /> Quay lại
            </button>

            <h2 className="text-2xl font-bold text-slate-800 mb-2">Nhập mã xác nhận</h2>
            <p className="text-slate-500 text-sm mb-8">Mã gồm 6 số đã được gửi đến email <span className="font-bold text-slate-700">{resetEmail}</span></p>

            <form onSubmit={handleVerifyOtp} className="space-y-8">
                {renderError()}
                <div className="flex gap-3 justify-center">
                    {otpCode.map((digit, index) => (
                        <input
                            key={index}
                            ref={el => inputRefs.current[index] = el}
                            type="text"
                            inputMode="numeric"
                            maxLength={1}
                            value={digit}
                            onChange={e => { handleOtpChange(e.target, index); setError(null); }}
                            onKeyDown={e => handleOtpKeyDown(e, index)}
                            onPaste={handleOtpPaste}
                            className={`w-12 h-14 text-center text-2xl font-bold bg-white border-2 rounded-xl focus:outline-none focus:ring-4 focus:ring-indigo-100 transition-all ${digit ? 'border-indigo-500 text-indigo-600' : 'border-slate-200 text-slate-700'}`}
                            autoFocus={index === 0}
                        />
                    ))}
                </div>

                <div className="text-center text-xs text-slate-400">
                    Chưa nhận được mã? <button type="button" className="text-indigo-600 font-bold hover:underline" onClick={() => alert("Đã gửi lại mã!")}>Gửi lại</button>
                </div>
                <button 
                    type="submit" 
                    disabled={isLoading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:bg-indigo-400"
                >
                    {isLoading ? 'Đang xác thực...' : 'Xác thực'}
                </button>
            </form>
        </div>
      )}

      {forgotStep === 'reset' && (
        <div className="animate-fade-in">
            <h2 className="text-2xl font-bold text-slate-800 mb-2">Đặt lại mật khẩu</h2>
            <p className="text-slate-500 text-sm mb-6">Vui lòng nhập mật khẩu mới cho tài khoản của bạn.</p>

            <form onSubmit={handleResetPassword} className="space-y-4">
                {renderError()}
                <div className="relative">
                    <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                        type="password" 
                        value={newPassword}
                        onChange={(e) => { setNewPassword(e.target.value); setError(null); }}
                        placeholder="Mật khẩu mới"
                        className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                        required
                        minLength={6}
                    />
                </div>
                <div className="relative">
                    <ShieldCheck className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                        type="password" 
                        value={confirmPassword}
                        onChange={(e) => { setConfirmPassword(e.target.value); setError(null); }}
                        placeholder="Xác nhận mật khẩu mới"
                        className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                        required
                        minLength={6}
                    />
                </div>
                <button 
                    type="submit" 
                    disabled={isLoading}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all disabled:bg-indigo-400"
                >
                    {isLoading ? 'Đang xử lý...' : 'Đổi mật khẩu'}
                </button>
            </form>
        </div>
      )}

      {forgotStep === 'success' && (
        <div className="bg-green-50 border border-green-100 rounded-lg p-6 text-center animate-fade-in mt-10">
          <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-3">
            <CheckCircle size={24} />
          </div>
          <h3 className="font-semibold text-slate-800 mb-1 text-lg">Thành công!</h3>
          <p className="text-sm text-slate-600 mb-6">Mật khẩu của bạn đã được thay đổi. Hãy đăng nhập lại với mật khẩu mới.</p>
          <button 
             onClick={resetForgotState}
             className="w-full bg-green-600 hover:bg-green-700 text-white font-medium py-3 rounded-lg shadow-sm transition-colors"
          >
            Về trang đăng nhập
          </button>
        </div>
      )}
    </div>
  );

  const CriteriaItem = ({ valid, text }: { valid: boolean, text: string }) => (
    <div className={`flex items-center gap-2 text-xs transition-colors duration-300 ${valid ? 'text-green-600 font-medium' : 'text-slate-400'}`}>
      <div className={`w-4 h-4 rounded-full flex items-center justify-center border ${valid ? 'bg-green-100 border-green-200' : 'bg-slate-50 border-slate-200'}`}>
        {valid && <Check size={10} />}
      </div>
      {text}
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-md rounded-2xl shadow-xl border border-slate-100 overflow-hidden">
        {view !== 'forgot' && (
          <div className="bg-indigo-600 p-8 text-center">
             <h1 className="text-3xl font-bold text-white mb-2">OmniSales</h1>
             <p className="text-indigo-100 text-sm">Quản lý bán hàng đa kênh thông minh</p>
          </div>
        )}

        {view === 'forgot' ? (
          renderForgotPassword()
        ) : (
          <div className="p-8">
            {/* View Switcher */}
            <div className="flex gap-4 mb-8 bg-slate-50 p-1 rounded-lg">
              <button 
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${view === 'login' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                onClick={() => setView('login')}
              >
                Đăng nhập
              </button>
              <button 
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-all ${view === 'register' ? 'bg-white shadow text-indigo-600' : 'text-slate-500 hover:text-slate-700'}`}
                onClick={() => setView('register')}
              >
                Đăng ký
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              {renderError()}

              {view === 'register' && (
                <div className="relative animate-fade-in">
                  <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    type="text" 
                    value={registerName}
                    onChange={(e) => setRegisterName(e.target.value)}
                    placeholder="Họ tên đầy đủ"
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                    required
                  />
                </div>
              )}

              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type="email" 
                  value={view === 'login' ? loginEmail : registerEmail}
                  onChange={(e) => { 
                      const val = e.target.value; 
                      view === 'login' ? setLoginEmail(val) : setRegisterEmail(val); 
                      setError(null);
                  }}
                  placeholder="Email của bạn"
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                  required
                />
              </div>

              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  type={showPassword ? "text" : "password"} 
                  placeholder="Mật khẩu"
                  className={`w-full pl-10 pr-10 py-3 bg-slate-50 border rounded-lg focus:outline-none focus:ring-2 transition-all ${
                    view === 'register' && !isPasswordValid && registerPassword.length > 0 
                    ? 'border-red-300 focus:ring-red-200' 
                    : 'border-slate-200 focus:ring-indigo-500'
                  }`}
                  value={view === 'register' ? registerPassword : loginPassword}
                  onChange={(e) => {
                      const val = e.target.value;
                      view === 'register' ? setRegisterPassword(val) : setLoginPassword(val);
                      setError(null);
                  }}
                  onFocus={() => setIsPasswordFocused(true)}
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>

              {/* Password Strength Meter (Register Only) */}
              {view === 'register' && (isPasswordFocused || registerPassword.length > 0) && (
                <div className="bg-slate-50 border border-slate-100 rounded-lg p-3 animate-fade-in space-y-2">
                   <p className="text-xs font-semibold text-slate-500 mb-1">Mật khẩu phải có:</p>
                   <div className="grid grid-cols-2 gap-2">
                      <CriteriaItem valid={passwordCriteria.length} text="Tối thiểu 8 ký tự" />
                      <CriteriaItem valid={passwordCriteria.hasNumber} text="Ít nhất 1 số" />
                      <CriteriaItem valid={passwordCriteria.hasLower} text="Chữ thường" />
                      <CriteriaItem valid={passwordCriteria.hasUpper} text="Chữ hoa" />
                   </div>
                </div>
              )}

              {/* DEMO ROLE SELECTION */}
              <div className="relative">
                <Briefcase className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <select 
                  value={selectedRole}
                  onChange={(e) => setSelectedRole(e.target.value as UserRole)}
                  className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all appearance-none text-slate-600"
                >
                  <option value="owner">Chủ Shop (Toàn quyền)</option>
                  <option value="employee">Nhân Viên (Quản lý đơn)</option>
                  <option value="collaborator">Cộng Tác Viên (Giới hạn shop)</option>
                </select>
                <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs text-slate-400 pointer-events-none">Demo Role</span>
              </div>

              {view === 'login' && (
                <div className="text-right">
                  <button 
                    type="button"
                    onClick={() => { setView('forgot'); setForgotStep('email'); setError(null); }}
                    className="text-xs text-indigo-600 hover:underline"
                  >
                    Quên mật khẩu?
                  </button>
                </div>
              )}

              <button 
                type="submit" 
                disabled={isLoading || (view === 'register' && !isPasswordValid)}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-medium py-3 rounded-lg flex items-center justify-center gap-2 transition-all mt-6 disabled:bg-slate-300 disabled:cursor-not-allowed"
              >
                {isLoading ? (
                  <span>Đang xử lý...</span>
                ) : (
                  <>
                    {view === 'login' ? 'Đăng nhập ngay' : 'Tạo tài khoản mới'}
                    <ArrowRight size={18} />
                  </>
                )}
              </button>
            </form>

            {/* Social Login Divider */}
            <div className="relative my-6">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-slate-200"></div>
              </div>
              <div className="relative flex justify-center text-sm">
                <span className="px-2 bg-white text-slate-500">Hoặc tiếp tục với</span>
              </div>
            </div>

            {/* Social Buttons */}
            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => handleSocialLogin('Google')}
                disabled={isLoading}
                className="flex items-center justify-center gap-2 px-4 py-2 border border-slate-200 rounded-lg hover:bg-slate-50 transition-colors disabled:opacity-50"
              >
                <GoogleIcon />
                <span className="text-sm font-medium text-slate-700">Google</span>
              </button>
              <button 
                onClick={() => handleSocialLogin('Apple')}
                disabled={isLoading}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-colors disabled:opacity-50"
              >
                <AppleIcon />
                <span className="text-sm font-medium">Apple</span>
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { MOCK_PRODUCTS, MOCK_INVENTORY_LOGS, MOCK_WAREHOUSES, MOCK_SUPPLIERS } from '../services/mockData';
import { InventoryLog, Warehouse, Product, Supplier } from '../types';
import { Search, ArrowUp, ArrowDown, History, Package, AlertTriangle, Filter, Save, Building, MapPin, X, Check, ChevronLeft, ChevronRight, Truck, Users, Plus, Phone, Mail, ArrowRight, Edit, User } from 'lucide-react';

type TransactionType = 'import' | 'export' | 'adjustment' | 'transfer';

const Inventory: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'overview' | 'logs' | 'suppliers'>('overview');
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedWarehouseId, setSelectedWarehouseId] = useState<string>('all');

  // Data State
  const [warehouses, setWarehouses] = useState<Warehouse[]>(MOCK_WAREHOUSES);
  const [products, setProducts] = useState(MOCK_PRODUCTS);
  const [logs, setLogs] = useState(MOCK_INVENTORY_LOGS);
  const [suppliers, setSuppliers] = useState<Supplier[]>(MOCK_SUPPLIERS);

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Warehouse Modal State
  const [isWarehouseModalOpen, setIsWarehouseModalOpen] = useState(false);
  const [newWarehouseData, setNewWarehouseData] = useState({
    name: '',
    address: '',
    manager: ''
  });

  // Transaction Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<TransactionType>('import');
  const [transactionData, setTransactionData] = useState({
    warehouseId: warehouses[0]?.id || '',
    toWarehouseId: warehouses[1]?.id || '',
    productId: '',
    quantity: 0,
    reason: '',
    supplierId: ''
  });
  const [productSearch, setProductSearch] = useState('');

  // Supplier Modal State
  const [isSupplierModalOpen, setIsSupplierModalOpen] = useState(false);
  const [supplierFormData, setSupplierFormData] = useState<Supplier>({
    id: '', name: '', code: '', phone: '', email: '', address: '', note: ''
  });
  const [editingSupplierId, setEditingSupplierId] = useState<string | null>(null);

  // Stats
  const calculateTotalStock = (p: Product) => {
    if (selectedWarehouseId === 'all') return p.stock;
    return p.warehouseStocks[selectedWarehouseId] || 0;
  };

  const currentProducts = products.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.sku.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalStock = currentProducts.reduce((acc, p) => acc + calculateTotalStock(p), 0);
  const totalValue = currentProducts.reduce((acc, p) => acc + (calculateTotalStock(p) * p.price), 0);
  const lowStockCount = currentProducts.filter(p => calculateTotalStock(p) < (p.minStock || 10)).length;

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
  };

  const getLogTypeColor = (type: InventoryLog['type']) => {
    switch (type) {
      case 'import': return 'text-green-600 bg-green-50';
      case 'export': return 'text-red-600 bg-red-50';
      case 'adjustment': return 'text-orange-600 bg-orange-50';
      case 'transfer': return 'text-blue-600 bg-blue-50';
      default: return 'text-slate-600 bg-slate-50';
    }
  };

  // Reset pagination when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [activeTab, searchTerm, selectedWarehouseId]);

  // Pagination Logic
  // For Overview
  const filteredProducts = currentProducts;
  const paginatedProducts = filteredProducts.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // For Logs
  const filteredLogs = logs.filter(log => selectedWarehouseId === 'all' || log.warehouseId === selectedWarehouseId || log.toWarehouseId === selectedWarehouseId);
  const paginatedLogs = filteredLogs.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // For Suppliers
  const filteredSuppliers = suppliers.filter(s => s.name.toLowerCase().includes(searchTerm.toLowerCase()) || s.phone.includes(searchTerm));
  const paginatedSuppliers = filteredSuppliers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const currentDataCount = activeTab === 'overview' ? filteredProducts.length : activeTab === 'logs' ? filteredLogs.length : filteredSuppliers.length;
  const totalPages = Math.ceil(currentDataCount / itemsPerPage);

  const indexOfLastItem = currentPage * itemsPerPage;
  const indexOfFirstItem = indexOfLastItem - itemsPerPage;

  // -- Warehouse Handlers --
  const handleAddWarehouse = () => {
    if (!newWarehouseData.name || !newWarehouseData.address) {
        alert("Vui lòng nhập tên kho và địa chỉ.");
        return;
    }
    const newWh: Warehouse = {
        id: `wh-${Date.now()}`,
        name: newWarehouseData.name,
        address: newWarehouseData.address,
        manager: newWarehouseData.manager || 'Chưa chỉ định'
    };
    setWarehouses([...warehouses, newWh]);
    setNewWarehouseData({ name: '', address: '', manager: '' });
    setIsWarehouseModalOpen(false);
    alert("Đã tạo kho hàng mới thành công!");
  };

  const selectedWarehouseInfo = warehouses.find(w => w.id === selectedWarehouseId);

  // -- Transaction Handlers --

  const openTransactionModal = (type: TransactionType) => {
    setModalType(type);
    setTransactionData({
       warehouseId: selectedWarehouseId === 'all' ? warehouses[0].id : selectedWarehouseId,
       toWarehouseId: warehouses[1]?.id || '',
       productId: '',
       quantity: 1,
       reason: '',
       supplierId: ''
    });
    setProductSearch('');
    setIsModalOpen(true);
  };

  const handleTransactionSubmit = () => {
     if (!transactionData.productId || transactionData.quantity <= 0) {
        alert("Vui lòng chọn sản phẩm và nhập số lượng hợp lệ.");
        return;
     }

     if (modalType === 'transfer' && transactionData.warehouseId === transactionData.toWarehouseId) {
        alert("Kho xuất và kho nhập không được trùng nhau.");
        return;
     }

     const product = products.find(p => p.id === transactionData.productId);
     if (!product) return;

     const warehouse = warehouses.find(w => w.id === transactionData.warehouseId);
     const toWarehouse = warehouses.find(w => w.id === transactionData.toWarehouseId);
     const supplier = suppliers.find(s => s.id === transactionData.supplierId);

     // Check stock for export/transfer
     if ((modalType === 'export' || modalType === 'transfer') && (product.warehouseStocks[transactionData.warehouseId] || 0) < transactionData.quantity) {
        alert("Số lượng tồn kho không đủ để thực hiện giao dịch.");
        return;
     }

     // Create Log
     const newLog: InventoryLog = {
        id: `LOG-${Date.now()}`,
        productId: product.id,
        productName: product.name,
        sku: product.sku,
        warehouseId: transactionData.warehouseId,
        warehouseName: warehouse ? warehouse.name : 'Unknown',
        toWarehouseId: modalType === 'transfer' ? transactionData.toWarehouseId : undefined,
        toWarehouseName: modalType === 'transfer' && toWarehouse ? toWarehouse.name : undefined,
        partnerName: modalType === 'import' && supplier ? supplier.name : undefined,
        type: modalType,
        quantity: modalType === 'export' ? -transactionData.quantity : transactionData.quantity, // For display logic mainly
        reason: transactionData.reason || (modalType === 'import' ? 'Nhập hàng' : modalType === 'export' ? 'Xuất hàng' : modalType === 'transfer' ? 'Chuyển kho' : 'Kiểm kê'),
        timestamp: new Date().toLocaleString('vi-VN'),
        performer: 'Admin'
     };

     setLogs([newLog, ...logs]);

     // Update Product Stock
     setProducts(prev => prev.map(p => {
        if (p.id === product.id) {
           const currentStocks = { ...p.warehouseStocks };

           if (modalType === 'import') {
              currentStocks[transactionData.warehouseId] = (currentStocks[transactionData.warehouseId] || 0) + transactionData.quantity;
           } else if (modalType === 'export') {
              currentStocks[transactionData.warehouseId] = (currentStocks[transactionData.warehouseId] || 0) - transactionData.quantity;
           } else if (modalType === 'adjustment') {
              // Assume quantity is the ADJUSTMENT amount (e.g., -2 or +5). UI handles this.
              currentStocks[transactionData.warehouseId] = (currentStocks[transactionData.warehouseId] || 0) + transactionData.quantity;
           } else if (modalType === 'transfer') {
              currentStocks[transactionData.warehouseId] = (currentStocks[transactionData.warehouseId] || 0) - transactionData.quantity;
              currentStocks[transactionData.toWarehouseId] = (currentStocks[transactionData.toWarehouseId] || 0) + transactionData.quantity;
           }

           const newTotalStock = Object.values(currentStocks).reduce((a: number, b: number) => a + b, 0);

           return {
              ...p,
              stock: newTotalStock,
              warehouseStocks: currentStocks
           };
        }
        return p;
     }));

     setIsModalOpen(false);
  };

  // -- Supplier Handlers --

  const handleEditSupplier = (supplier: Supplier) => {
    setSupplierFormData(supplier);
    setEditingSupplierId(supplier.id);
    setIsSupplierModalOpen(true);
  };

  const handleAddSupplier = () => {
    setSupplierFormData({ id: '', name: '', code: '', phone: '', email: '', address: '', note: '' });
    setEditingSupplierId(null);
    setIsSupplierModalOpen(true);
  };

  const handleSaveSupplier = () => {
     if (!supplierFormData.name || !supplierFormData.phone) {
        alert("Vui lòng nhập tên và số điện thoại nhà cung cấp.");
        return;
     }

     if (editingSupplierId) {
        setSuppliers(prev => prev.map(s => s.id === editingSupplierId ? { ...supplierFormData, id: editingSupplierId } : s));
     } else {
        const newSup = { ...supplierFormData, id: `sup-${Date.now()}`, code: supplierFormData.code || `SUP${Date.now().toString().slice(-4)}` };
        setSuppliers(prev => [newSup, ...prev]);
     }
     setIsSupplierModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-10">
      <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
        <div>
           <h2 className="text-2xl font-bold text-slate-800">Quản lý Kho hàng</h2>
           <p className="text-sm text-slate-500">Theo dõi tồn kho, nhập xuất và điều chuyển giữa các kho.</p>
        </div>

        {/* Warehouse Selector */}
        <div className="flex items-center gap-2 bg-white p-1 rounded-lg border border-slate-200 shadow-sm overflow-x-auto no-scrollbar max-w-full">
           <div className={`px-3 py-1.5 rounded-md text-sm font-medium cursor-pointer transition-colors whitespace-nowrap ${selectedWarehouseId === 'all' ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-50'}`} onClick={() => setSelectedWarehouseId('all')}>
              Tất cả kho
           </div>
           {warehouses.map(wh => (
              <div 
                key={wh.id} 
                onClick={() => setSelectedWarehouseId(wh.id)}
                className={`px-3 py-1.5 rounded-md text-sm font-medium cursor-pointer transition-colors flex items-center gap-1 whitespace-nowrap ${selectedWarehouseId === wh.id ? 'bg-indigo-600 text-white' : 'text-slate-600 hover:bg-slate-50'}`}
              >
                 <Building size={14} /> {wh.name}
              </div>
           ))}
           <button 
             onClick={() => setIsWarehouseModalOpen(true)}
             className="px-2 py-1.5 rounded-md text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 border border-dashed border-slate-300 ml-1 transition-colors"
             title="Thêm kho mới"
           >
             <Plus size={16} />
           </button>
        </div>
      </div>

      <div className="flex flex-wrap gap-3">
          <button onClick={() => openTransactionModal('import')} className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors shadow-sm font-medium">
             <ArrowDown size={18} /> Nhập kho
          </button>
          <button onClick={() => openTransactionModal('export')} className="flex items-center gap-2 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors shadow-sm font-medium">
             <ArrowUp size={18} /> Xuất kho
          </button>
          <button onClick={() => openTransactionModal('transfer')} className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors shadow-sm font-medium">
             <ArrowRight size={18} /> Chuyển kho
          </button>
          <button onClick={() => openTransactionModal('adjustment')} className="flex items-center gap-2 px-4 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition-colors shadow-sm font-medium">
             <Save size={18} /> Kiểm kê
          </button>
      </div>

      {/* Info Card when specific warehouse is selected */}
      {selectedWarehouseId !== 'all' && selectedWarehouseInfo && (
        <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl flex flex-col sm:flex-row sm:items-center justify-between gap-4 animate-fade-in">
            <div className="flex gap-4">
                <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-indigo-600 shadow-sm border border-indigo-100">
                    <Building size={24} />
                </div>
                <div>
                    <h3 className="font-bold text-indigo-900 text-lg">{selectedWarehouseInfo.name}</h3>
                    <div className="flex flex-wrap gap-3 text-sm text-indigo-700 mt-1">
                        <span className="flex items-center gap-1"><MapPin size={14}/> {selectedWarehouseInfo.address}</span>
                        <span className="flex items-center gap-1"><User size={14}/> Quản lý: {selectedWarehouseInfo.manager}</span>
                    </div>
                </div>
            </div>
            <div className="text-right">
                <div className="text-xs text-indigo-600 uppercase font-bold tracking-wider">Tổng giá trị kho</div>
                <div className="text-xl font-bold text-indigo-900">{formatCurrency(totalValue)}</div>
            </div>
        </div>
      )}

      {/* Stats Cards (Hidden if warehouse info card above is sufficient, or kept for summary) */}
      {selectedWarehouseId === 'all' && (
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
           <div>
             <p className="text-slate-500 text-sm font-medium">Tổng giá trị tồn kho</p>
             <h3 className="text-2xl font-bold text-slate-800 mt-1">{formatCurrency(totalValue)}</h3>
             <p className="text-xs text-slate-400 mt-1">Toàn hệ thống</p>
           </div>
           <div className="p-3 bg-indigo-50 text-indigo-600 rounded-lg">
             <Package size={24} />
           </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
           <div>
             <p className="text-slate-500 text-sm font-medium">Tổng sản phẩm tồn</p>
             <h3 className="text-2xl font-bold text-slate-800 mt-1">{totalStock.toLocaleString()}</h3>
           </div>
           <div className="p-3 bg-blue-50 text-blue-600 rounded-lg">
             <Package size={24} />
           </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100 flex items-center justify-between">
           <div>
             <p className="text-slate-500 text-sm font-medium">Cảnh báo sắp hết</p>
             <h3 className="text-2xl font-bold text-red-600 mt-1">{lowStockCount}</h3>
           </div>
           <div className="p-3 bg-red-50 text-red-600 rounded-lg animate-pulse">
             <AlertTriangle size={24} />
           </div>
        </div>
      </div>
      )}

      {/* Tabs */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 overflow-hidden min-h-[500px] flex flex-col">
        <div className="flex border-b border-slate-100 shrink-0 overflow-x-auto">
           <button 
             onClick={() => setActiveTab('overview')}
             className={`px-6 py-4 text-sm font-medium flex items-center gap-2 transition-colors border-b-2 whitespace-nowrap ${activeTab === 'overview' ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
           >
             <Package size={16} /> Tồn kho hiện tại
           </button>
           <button 
             onClick={() => setActiveTab('logs')}
             className={`px-6 py-4 text-sm font-medium flex items-center gap-2 transition-colors border-b-2 whitespace-nowrap ${activeTab === 'logs' ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
           >
             <History size={16} /> Lịch sử giao dịch
           </button>
           <button 
             onClick={() => setActiveTab('suppliers')}
             className={`px-6 py-4 text-sm font-medium flex items-center gap-2 transition-colors border-b-2 whitespace-nowrap ${activeTab === 'suppliers' ? 'border-indigo-600 text-indigo-600 bg-indigo-50/50' : 'border-transparent text-slate-500 hover:text-indigo-600'}`}
           >
             <Users size={16} /> Nhà cung cấp
           </button>
        </div>

        {/* Content */}
        <div className="p-6 flex-1 flex flex-col">
           <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
              <div className="relative w-full sm:w-80">
                 <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                 <input 
                   type="text" 
                   value={searchTerm}
                   onChange={(e) => setSearchTerm(e.target.value)}
                   placeholder={activeTab === 'suppliers' ? "Tìm nhà cung cấp..." : "Tìm kiếm mã SKU, tên sản phẩm..."}
                   className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500"
                 />
              </div>
              <div className="flex gap-2 w-full sm:w-auto">
                 {activeTab === 'suppliers' && (
                    <button onClick={handleAddSupplier} className="flex items-center gap-2 px-3 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium transition-colors shadow-sm">
                       <Plus size={16} /> Thêm NCC
                    </button>
                 )}
                 {activeTab !== 'suppliers' && (
