    syncPrice: true,
    syncInfo: false,
  });
  const [isSyncing, setIsSyncing] = useState(false);

  // Import State
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);

  // Bulk Edit State
  const [bulkEditPercent, setBulkEditPercent] = useState<number>(0);

