const InstructionBox = ({ title, steps }: { title: string, steps: string[] }) => (
  <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-4 mb-6 flex items-start gap-3 shadow-sm">
    <Info className="text-indigo-600 shrink-0 mt-0.5" size={20} />
    <div>
      <h4 className="font-bold text-indigo-900 text-sm mb-2">{title}</h4>
      <ul className="text-xs text-indigo-800 space-y-1.5 list-disc pl-4 leading-relaxed">
        {steps.map((step, idx) => <li key={idx}>{step}</li>)}
      </ul>
    </div>
  </div>
);

// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
}

const Tools: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'import' | 'listing' | 'sync' | 'bulkedit' | 'keywords'>('import');

  // Listing State
  const [listingFilter, setListingFilter] = useState('all');
  const [isListingModalOpen, setIsListingModalOpen] = useState(false);
  const [listingStep, setListingStep] = useState(1); // 1: Source, 2: Target, 3: Product, 4: Edit
  const [listingSource, setListingSource] = useState<'system' | 'shop' | 'link'>('system');
  const [listingSelectedShops, setListingSelectedShops] = useState<string[]>([]);
  const [listingSelectedProducts, setListingSelectedProducts] = useState<string[]>([]);

  // Shop Sync State
  const [syncConfig, setSyncConfig] = useState({
    sourceShopId: '',
    targetShopIds: [] as string[],
    syncStock: true,
    syncPrice: true,
    syncInfo: false,
  });
  const [isSyncing, setIsSyncing] = useState(false);

  // Import State (Redesigned)
  const [importConfig, setImportConfig] = useState({
      sourceShopId: '',
      targetWarehouseId: MOCK_WAREHOUSES[0].id,
      pricePolicy: 'retail' as 'retail' | 'wholesale' | 'import'
  });
  const [sourceProducts, setSourceProducts] = useState<SourceProduct[]>([]);
  const [selectedImportIds, setSelectedImportIds] = useState<string[]>([]);
  const [isImporting, setIsImporting] = useState(false);

  // Bulk Edit State
  const [bulkEditPercent, setBulkEditPercent] = useState<number>(0);

  // Forbidden Keywords State
  const [keywordsList, setKeywordsList] = useState(MOCK_FORBIDDEN_KEYWORDS);
  const [selectedCategory, setSelectedCategory] = useState<string>('Thương hiệu/MXH');
  const [isKeywordModalOpen, setIsKeywordModalOpen] = useState(false);
  const [keywordForm, setKeywordForm] = useState({ id: '', text: '', category: '' });

  // Flatten shops list for selection
  const allShops = INITIAL_INTEGRATIONS.flatMap(i => i.shops.map(s => ({ ...s, platform: i.platform })));

  const tabs = [
    { id: 'import', label: 'Sao chép sản phẩm', icon: Download },
    { id: 'listing', label: 'Đăng bán sản phẩm', icon: UploadCloud },
    { id: 'sync', label: 'Đồng bộ Shop chéo', icon: ArrowRightLeft },
    { id: 'bulkedit', label: 'Sửa giá hàng loạt', icon: Edit3 },
    { id: 'keywords', label: 'Từ khóa cấm', icon: ShieldBan },
  ];

  const handleShopSync = () => {
    if (!syncConfig.sourceShopId || syncConfig.targetShopIds.length === 0) {
      alert("Vui lòng chọn Shop nguồn và ít nhất 1 Shop đích.");
      return;
    }
    setIsSyncing(true);
    // Simulate API call
    setTimeout(() => {
      setIsSyncing(false);
      alert(`Đồng bộ thành công từ shop nguồn sang ${syncConfig.targetShopIds.length} shop đích!`);
    }, 2000);
  };

  const toggleTargetShop = (shopId: string) => {
    setSyncConfig(prev => {
      const exists = prev.targetShopIds.includes(shopId);
      return {
        ...prev,
        targetShopIds: exists 
          ? prev.targetShopIds.filter(id => id !== shopId)
          : [...prev.targetShopIds, shopId]
      };
    });
  };

  // --- Import Logic ---
  // Simulate fetching products from a shop
  useEffect(() => {
      if (importConfig.sourceShopId) {
          // Generate mock source products based on MOCK_PRODUCTS but add some variation
          const mockSource: SourceProduct[] = MOCK_PRODUCTS.slice(0, 15).map(p => {
              const hasSku = Math.random() > 0.2; // 20% chance of missing SKU
              const exists = hasSku && Math.random() > 0.5; // Randomly exists in OmniSales

              return {
                  id: `src-${p.id}`,
                  name: p.name,
                  sku: hasSku ? p.sku : '', // Simulate missing SKU
                  price: p.price,
                  stock: p.stock,
                  image: p.image,
                  weight: 500,
                  description: p.description,
                  status: 'active',
                  existsInOmni: exists,
                  isCopied: false
              };
          });
          setSourceProducts(mockSource);
          setSelectedImportIds([]);
      } else {
          setSourceProducts([]);
      }
  }, [importConfig.sourceShopId]);

  const toggleImportSelection = (id: string) => {
      setSelectedImportIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const handleCopyProducts = () => {
      if (selectedImportIds.length === 0) return alert("Vui lòng chọn sản phẩm để sao chép.");

      setIsImporting(true);
      setTimeout(() => {
          setIsImporting(false);
          setSourceProducts(prev => prev.map(p => 
              selectedImportIds.includes(p.id) ? { ...p, isCopied: true, existsInOmni: true } : p
          ));
          setSelectedImportIds([]);
          alert(`Đã sao chép thành công ${selectedImportIds.length} sản phẩm về kho ${MOCK_WAREHOUSES.find(w => w.id === importConfig.targetWarehouseId)?.name}!`);
      }, 1500);
  };

  // --- Listing Wizard Handlers ---
  const toggleListingShop = (shopId: string) => {
    setListingSelectedShops(prev => 
      prev.includes(shopId) ? prev.filter(id => id !== shopId) : [...prev, shopId]
    );
  };

  const toggleListingProduct = (productId: string) => {
    setListingSelectedProducts(prev => 
      prev.includes(productId) ? prev.filter(id => id !== productId) : [...prev, productId]
    );
  };

  const resetListingWizard = () => {
    setIsListingModalOpen(false);
    setListingStep(1);
    setListingSelectedShops([]);
    setListingSelectedProducts([]);
  };

  // --- Keyword Handlers ---
  const categories = useMemo(() => Array.from(new Set(keywordsList.map(k => k.category))), [keywordsList]);

  const handleAddKeyword = () => {
    setKeywordForm({ id: '', text: '', category: selectedCategory });
    setIsKeywordModalOpen(true);
  };

  const handleEditKeyword = (kw: { id: string, text: string, category: string }) => {
    setKeywordForm(kw);
    setIsKeywordModalOpen(true);
  };

  const handleDeleteKeyword = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa từ khóa này?')) {
      setKeywordsList(prev => prev.filter(k => k.id !== id));
    }
  };

  const handleSaveKeyword = () => {
    if (!keywordForm.text || !keywordForm.category) {
      alert('Vui lòng nhập từ khóa và chọn chủ đề.');
      return;
    }

    if (keywordForm.id) {
      // Edit
      setKeywordsList(prev => prev.map(k => k.id === keywordForm.id ? keywordForm : k));
    } else {
      // Add
      setKeywordsList(prev => [...prev, { ...keywordForm, id: `kw-${Date.now()}` }]);
    }
    setIsKeywordModalOpen(false);
  };

  const renderListingTool = () => {
    const filters = [
      { id: 'all', label: 'Tất cả các sản phẩm' },
      { id: 'success', label: 'Thành công' },
      { id: 'failed', label: 'Thất bại' },
      { id: 'draft', label: 'Lưu nháp' },
      { id: 'partial', label: 'Thành công một phần' },
      { id: 'processing', label: 'Đang xử lý' },
    ];

    const getStatusBadge = (status: string) => {
      switch (status) {
        case 'success': return <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-bold border border-green-200">Thành công</span>;
        case 'failed': return <span className="bg-red-100 text-red-700 px-3 py-1 rounded-full text-xs font-bold border border-red-200">Thất bại</span>;
        case 'draft': return <span className="bg-slate-100 text-slate-700 px-3 py-1 rounded-full text-xs font-bold border border-slate-200">Lưu nháp</span>;
        case 'partial': return <span className="bg-orange-100 text-orange-700 px-3 py-1 rounded-full text-xs font-bold border border-orange-200">Thành công một phần</span>;
        case 'processing': return <span className="bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-xs font-bold border border-blue-100">Đang xử lý</span>;
        default: return null;
      }
    };

    const filteredListings = MOCK_LISTINGS.filter(l => listingFilter === 'all' || l.status === listingFilter);

    return (
      <div className="space-y-4 animate-fade-in h-full flex flex-col">
        <InstructionBox 
            title="Hướng dẫn Đăng bán sản phẩm đa sàn"
            steps={[
                "Bước 1: Nhấn 'Đăng bán sản phẩm mới' và chọn nguồn dữ liệu (từ Hệ thống, từ Shop khác hoặc Link sản phẩm).",
                "Bước 2: Chọn các gian hàng đích bạn muốn đăng bán lên (Ví dụ: Shopee A, Lazada B).",
                "Bước 3: Chọn sản phẩm cần đăng và chỉnh sửa thông tin (Tên, Giá, Ảnh) cho phù hợp với từng sàn.",
                "Bước 4: Nhấn 'Đăng bán ngay' để hệ thống tự động đẩy sản phẩm lên các sàn đã chọn."
            ]}
        />

        {/* Header */}
        <div className="flex justify-between items-center bg-white p-4 rounded-xl border border-slate-100 shadow-sm">
           <div>
              <h3 className="font-bold text-lg text-slate-800">Danh sách sản phẩm đăng bán</h3>
              <p className="text-sm text-slate-500">Quản lý và đăng tải sản phẩm lên các sàn TMĐT.</p>
           </div>
           <button 
             onClick={() => setIsListingModalOpen(true)}
             className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 shadow-sm transition-colors"
           >
             <UploadCloud size={18} /> Đăng bán sản phẩm mới
           </button>
        </div>

        {/* Filter Tabs */}
        <div className="bg-white border-b border-slate-200 rounded-t-xl overflow-x-auto">
           <div className="flex w-max">
              {filters.map(filter => (
                <button
                  key={filter.id}
                  onClick={() => setListingFilter(filter.id)}
                  className={`px-5 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${listingFilter === filter.id ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-500 hover:text-slate-700'}`}
                >
                  {filter.label}
                </button>
              ))}
           </div>
        </div>

        {/* Toolbar */}
        <div className="bg-white p-4 border border-t-0 border-slate-200 shadow-sm flex flex-col sm:flex-row gap-4 items-center">
           <div className="relative flex-1 w-full">
              <input 
                type="text" 
                placeholder="Tìm kiếm sản phẩm đăng bán..." 
                className="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              />
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
           </div>
           <div className="flex gap-2 w-full sm:w-auto">
              <button className="px-4 py-2 border border-slate-200 rounded-lg text-slate-600 text-sm hover:bg-slate-50 flex items-center gap-2">
                 <Filter size={16} /> Lọc sản phẩm
              </button>
           </div>
        </div>

        {/* Data Table */}
        <div className="flex-1 bg-white border border-slate-200 rounded-b-xl shadow-sm overflow-hidden flex flex-col">
           <div className="overflow-auto flex-1">
              <table className="w-full text-sm text-left">
                 <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                    <tr>
                       <th className="px-6 py-4 w-12 text-center"><input type="checkbox" className="rounded" /></th>
                       <th className="px-6 py-4">Danh sách sản phẩm</th>
                       <th className="px-6 py-4">Thời gian tạo/sửa</th>
                       <th className="px-6 py-4">Trạng thái</th>
                       <th className="px-6 py-4">Sàn đăng bán</th>
                       <th className="px-6 py-4 text-center">Thao tác</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-100">
                    {filteredListings.map(item => (
                       <tr key={item.id} className="hover:bg-slate-50 group">
                          <td className="px-6 py-4 text-center"><input type="checkbox" className="rounded" /></td>
                          <td className="px-6 py-4">
                             <div className="flex items-center gap-3">
                                <img src={item.image} alt="" className="w-12 h-12 rounded object-cover border border-slate-200 bg-white" />
                                <span className="font-medium text-blue-600 hover:underline cursor-pointer line-clamp-2 max-w-md">{item.productName}</span>
                             </div>
                          </td>
                          <td className="px-6 py-4 text-slate-500">{item.updatedAt}</td>
                          <td className="px-6 py-4">{getStatusBadge(item.status)}</td>
                          <td className="px-6 py-4">
                             {item.platforms.length > 0 ? (
                                <div className="flex items-center gap-2">
                                   {item.platforms.length > 1 ? (
                                      <div className="flex items-center gap-1 text-slate-600 font-medium">
                                         <Store size={16} className="text-blue-500" /> Đa sàn
                                      </div>
                                   ) : (
                                      <div className="flex items-center gap-2">
                                         {item.platforms.map(p => (
                                            <div key={p} className="flex items-center gap-1 bg-slate-50 px-2 py-1 rounded border border-slate-100">
                                               {LOGOS[p] && <img src={LOGOS[p]} className="w-4 h-4 object-contain" />}
                                               <span>{p}</span>
                                            </div>
                                         ))}
                                      </div>
                                   )}
                                </div>
                             ) : <span className="text-slate-400">-</span>}
                          </td>
                          <td className="px-6 py-4 text-center">
                             <button className="text-slate-400 hover:text-blue-600 p-2"><Edit3 size={18} /></button>
                          </td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      </div>
    );
  };

  const renderProductImport = () => (
    <div className="space-y-6 animate-fade-in">
       <InstructionBox 
            title="Hướng dẫn Sao chép sản phẩm (Import)"
            steps={[
                "Bước 1: Chọn 'Gian hàng nguồn' để lấy dữ liệu.",
                "Bước 2: Chọn 'Kho hàng đích' và 'Chính sách giá' để lưu trữ thông tin trên OmniSales.",
                "Bước 3: Tích chọn các sản phẩm bạn muốn sao chép (Chỉ áp dụng với sản phẩm có mã SKU).",
                "Bước 4: Nhấn 'Sao chép sản phẩm' để hệ thống tự động khởi tạo dữ liệu."
            ]}
       />

       <div className="bg-white rounded-xl shadow-sm border border-slate-100 p-6">
          <div className="mb-6 pb-6 border-b border-slate-100">
             <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2 mb-4">
                <Download className="text-indigo-600" /> Cấu hình Sao chép
             </h3>

             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-2">1. Chọn Gian hàng nguồn</label>
                   <select 
                      value={importConfig.sourceShopId}
                      onChange={(e) => setImportConfig({...importConfig, sourceShopId: e.target.value})}
                      className="w-full border-slate-200 rounded-lg px-3 py-2.5 text-sm focus:ring-indigo-500 focus:border-indigo-500 bg-slate-50"
                   >
                      <option value="">-- Chọn gian hàng --</option>
                      {allShops.map(shop => (
                         <option key={shop.id} value={shop.id}>[{shop.platform}] {shop.name}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-2">2. Kho hàng nhận (Đích)</label>
                   <select 
                      value={importConfig.targetWarehouseId}
                      onChange={(e) => setImportConfig({...importConfig, targetWarehouseId: e.target.value})}
                      className="w-full border-slate-200 rounded-lg px-3 py-2.5 text-sm focus:ring-indigo-500 focus:border-indigo-500 bg-slate-50"
                   >
                      {MOCK_WAREHOUSES.map(wh => (
                         <option key={wh.id} value={wh.id}>{wh.name}</option>
                      ))}
                   </select>
                </div>
                <div>
                   <label className="block text-sm font-medium text-slate-700 mb-2">3. Chính sách giá khởi tạo</label>
                   <select 
                      value={importConfig.pricePolicy}
                      onChange={(e) => setImportConfig({...importConfig, pricePolicy: e.target.value as any})}
                      className="w-full border-slate-200 rounded-lg px-3 py-2.5 text-sm focus:ring-indigo-500 focus:border-indigo-500 bg-slate-50"
                   >
                      <option value="retail">Giá bán lẻ (Mặc định)</option>
                      <option value="wholesale">Giá bán buôn</option>
                      <option value="import">Giá nhập (Vốn)</option>
                   </select>
                </div>
             </div>
          </div>

          <div className="mb-4 flex justify-between items-center">
             <div className="text-sm font-medium text-slate-700">
                Danh sách sản phẩm ({sourceProducts.length})
             </div>
             <div className="flex gap-2">
                <button 
                   className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50"
                   disabled={isImporting || !importConfig.sourceShopId}
                >
                   Làm mới
                </button>
                <button 
                   onClick={handleCopyProducts}
                   disabled={isImporting || selectedImportIds.length === 0}
                   className="px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-sm hover:bg-indigo-700 disabled:bg-slate-300 disabled:cursor-not-allowed flex items-center gap-2"
                >
                   {isImporting ? <RefreshCw className="animate-spin" size={16}/> : <Copy size={16}/>}
                   {isImporting ? 'Đang xử lý...' : `Sao chép (${selectedImportIds.length})`}
                </button>
             </div>
          </div>

          {/* Product Table */}
          <div className="border border-slate-200 rounded-lg overflow-hidden max-h-[500px] overflow-y-auto">
             <table className="w-full text-sm text-left">
                <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-200 sticky top-0 z-10">
                   <tr>
                      <th className="px-4 py-3 w-10 text-center">
                         <input 
                            type="checkbox" 
                            disabled={!sourceProducts.some(p => p.sku)}
