      if (listingSelectedProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");

      const listingSelectedSelectedShopsNames = allShops.filter(s => listingSelectedShops.includes(s.id)).map(s => s.name);

      const confirmPublish = window.confirm(
