      if (confirmPublish) {
          alert("Đã gửi yêu cầu đăng bán thành công! Sản phẩm sẽ sớm xuất hiện trên sàn.");
          resetListingWizard();
      }
  };

  // --- Existing Listing Edit Handlers ---
  const handleEditListing = (listing: any) => {
