                          </div>
                          <div>
                              <label className="block text-xs font-bold text-slate-500 mb-1">Thời gian tạo</label>
                              <div className="flex gap-2">
                                  <input type="date" className="w-full border border-slate-200 rounded-lg px-2 py-1.5 text-xs" />
                                  <input type="date" className="w-full border border-slate-200 rounded-lg px-2 py-1.5 text-xs" />
