  };

  const renderListingWizard = () => {
    if (!isListingModalOpen) return null;

    // Helper to get selected products data
    const productsToPublish = MOCK_PRODUCTS.filter(p => listingSelectedProducts.includes(p.id));

    return (
      <div className="fixed inset-0 bg-black/60 z-[70] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
         <div className="bg-white rounded-xl shadow-2xl w-full max-w-5xl h-[90vh] flex flex-col overflow-hidden">
            {/* Header */}
            <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
               <div>
                  <h3 className="font-bold text-lg text-slate-800">Đăng bán sản phẩm mới</h3>
                  <div className="flex items-center gap-2 text-xs text-slate-500 mt-1">
                     <span className={`font-bold ${listingStep >= 1 ? 'text-indigo-600' : ''}`}>1. Chọn nguồn</span>
                     <ChevronRight size={12} />
                     <span className={`font-bold ${listingStep >= 2 ? 'text-indigo-600' : ''}`}>2. Chọn Shop đích</span>
                     <ChevronRight size={12} />
                     <span className={`font-bold ${listingStep >= 3 ? 'text-indigo-600' : ''}`}>3. Chọn sản phẩm</span>
                     <ChevronRight size={12} />
                     <span className={`font-bold ${listingStep >= 4 ? 'text-indigo-600' : ''}`}>4. Tối ưu & Đăng bán</span>
