               <button onClick={resetListingWizard}><X size={24} className="text-slate-400 hover:text-slate-600"/></button>
            </div>

            {/* Body */}
            <div className="flex-1 overflow-y-auto p-6">
               {listingStep === 1 && (
                  <div className="space-y-4 max-w-xl mx-auto py-10">
                     <h4 className="text-center font-bold text-slate-700 mb-6">Bạn muốn lấy dữ liệu sản phẩm từ đâu?</h4>
                     <button 
                       onClick={() => setListingSource('system')}
                       className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 transition-all ${listingSource === 'system' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300'}`}
                     >
                        <div className="w-12 h-12 rounded-full bg-white flex items-center justify-center text-indigo-600 shadow-sm border border-slate-100">
                           <Store size={24} />
                        </div>
                        <div className="text-left">
                           <div className="font-bold text-slate-800">Từ Hệ thống OmniSales</div>
                           <div className="text-xs text-slate-500">Sản phẩm đã có trong kho hàng hệ thống</div>
                        </div>
                        {listingSource === 'system' && <CheckCircle2 className="ml-auto text-indigo-600" size={24} />}
                     </button>

                     <button 
                       onClick={() => setListingSource('shop')}
                       className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 transition-all ${listingSource === 'shop' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300'}`}
                     >
                        <div className="w-12 h-12 rounded-full bg-white flex items-center justify-center text-orange-600 shadow-sm border border-slate-100">
                           <RefreshCw size={24} />
                        </div>
                        <div className="text-left">
                           <div className="font-bold text-slate-800">Từ Shop đang liên kết</div>
                           <div className="text-xs text-slate-500">Sao chép từ Shopee, Lazada, TikTok...</div>
                        </div>
                        {listingSource === 'shop' && <CheckCircle2 className="ml-auto text-indigo-600" size={24} />}
                     </button>

                     <button 
                       onClick={() => setListingSource('link')}
                       className={`w-full p-4 rounded-xl border-2 flex items-center gap-4 transition-all ${listingSource === 'link' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 hover:border-indigo-300'}`}
                     >
                        <div className="w-12 h-12 rounded-full bg-white flex items-center justify-center text-blue-600 shadow-sm border border-slate-100">
                           <LinkIcon size={24} />
                        </div>
                        <div className="text-left">
                           <div className="font-bold text-slate-800">Từ Đường dẫn (Link)</div>
                           <div className="text-xs text-slate-500">Dán link sản phẩm Shopee/1688/Taobao...</div>
