                                    <td className="px-4 py-3 text-center">{p.stock}</td>
                                 </tr>
                              ))}
                           </tbody>
                        </table>
                     </div>
                  </div>
               )}

               {listingStep === 4 && (
                   <div className="space-y-6 animate-fade-in">
