                               </p>
                           </div>
                       </div>

                       <div className="border border-slate-200 rounded-xl overflow-hidden">
                           <table className="w-full text-sm text-left">
                               <thead className="bg-slate-50 text-slate-600 font-semibold border-b border-slate-200">
                                   <tr>
                                       <th className="px-6 py-4">Sản phẩm</th>
                                       <th className="px-6 py-4 w-40 text-right">Giá bán (VND)</th>
                                       <th className="px-6 py-4 w-32 text-center">Tồn kho</th>
                                   </tr>
                               </thead>
                               <tbody className="divide-y divide-slate-100">
                                   {productsToPublish.map(p => (
                                       <tr key={p.id} className="hover:bg-slate-50">
                                           <td className="px-6 py-4">
                                               <div className="flex items-center gap-3">
                                                   <img src={p.image} className="w-10 h-10 rounded border border-slate-200 object-cover" />
                                                   <div className="min-w-0">
                                                       <div className="font-bold text-slate-800 truncate max-w-sm">{p.name}</div>
                                                       <div className="text-xs text-slate-500">{p.sku}</div>
                                                   </div>
                                               </div>
                                           </td>
                                           <td className="px-6 py-4 text-right">
                                               <input 
                                                   type="text" 
                                                   value={formatInputNumber(listingEdits[p.id]?.price ?? p.price)}
                                                   onChange={(e) => handleListingEditChange(p.id, 'price', e.target.value)}
                                                   className="w-full border border-slate-200 rounded px-2 py-1 text-right focus:border-indigo-500 outline-none font-medium"
                                               />
                                           </td>
                                           <td className="px-6 py-4 text-center">
                                               <input 
                                                   type="number" 
                                                   value={listingEdits[p.id]?.stock ?? p.stock}
                                                   onChange={(e) => handleListingEditChange(p.id, 'stock', e.target.value)}
                                                   className="w-full border border-slate-200 rounded px-2 py-1 text-center focus:border-indigo-500 outline-none"
                                               />
                                           </td>
                                       </tr>
                                   ))}
                               </tbody>
                           </table>
                       </div>
                   </div>
               )}
            </div>

            {/* Footer */}
            <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-between items-center">
               <button 
                  onClick={() => setListingStep(prev => Math.max(1, prev - 1))}
                  className={`px-4 py-2 border border-slate-200 bg-white rounded-lg text-slate-600 font-medium hover:bg-slate-100 ${listingStep === 1 ? 'invisible' : ''}`}
               >
                  Quay lại
               </button>
               <div className="flex gap-2">
                  <button onClick={resetListingWizard} className="px-4 py-2 text-slate-500 hover:text-slate-700 font-medium">Hủy bỏ</button>
                  {listingStep < 4 ? (
                     <button 
                        onClick={() => setListingStep(prev => prev + 1)}
                        disabled={(listingStep === 2 && listingSelectedShops.length === 0) || (listingStep === 3 && listingSelectedProducts.length === 0)}
                        className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold shadow-sm hover:bg-indigo-700 disabled:bg-slate-300 disabled:cursor-not-allowed"
                     >
                        Tiếp tục
                     </button>
                  ) : (
                     <button 
                        onClick={handlePublishListing}
                        className="px-6 py-2 bg-green-600 text-white rounded-lg font-bold shadow-sm hover:bg-green-700 flex items-center gap-2"
                     >
                        <Rocket size={18} /> Đăng bán ngay
                     </button>
                  )}
               </div>
            </div>
         </div>
      </div>
    );
  };

  return (
    <div className="pb-10">
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-slate-800">Công cụ quản lý</h2>
        <p className="text-sm text-slate-500">Đồng bộ và quản lý dữ liệu sản phẩm trên diện rộng.</p>
      </div>

      {/* Navigation Tabs (Top) */}
      <div className="flex overflow-x-auto no-scrollbar gap-2 mb-6 bg-white p-2 rounded-xl border border-slate-100 shadow-sm">
        {tabs.map(tab => {
          const Icon = tab.icon;
          const isActive = activeTab === tab.id;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                isActive 
                  ? 'bg-indigo-600 text-white shadow-md' 
                  : 'text-slate-600 hover:bg-slate-50'
              }`}
            >
              <Icon size={18} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Content Area */}
      <div>
         {activeTab === 'import' && renderProductImport()}
         {activeTab === 'listing' && renderListingTool()}
         {activeTab === 'sync' && renderShopSync()}
         {activeTab === 'bulkedit' && renderBulkEdit()}
         {activeTab === 'keywords' && renderForbiddenKeywords()}
      </div>

      {/* Listing Wizard Modal */}
      {renderListingWizard()}

      {/* Import Progress Modal */}
      {renderImportProgressModal()}

      {/* Publish Progress Modal */}
      {renderPublishProgressModal()}

      {/* Sync Progress Modal */}
      {renderSyncProgressModal()}
    </div>
  );
};

export default Tools;

