                              <span className="font-bold ml-1">{viewingHistoryDetail.action}</span>
                          </div>
                          <div>
                              <span className="text-slate-500">Thời gian:</span> 
                              <span className="font-bold ml-1">{viewingHistoryDetail.timestamp}</span>
                          </div>
                      </div>
                  </div>

                  <div className="flex-1 overflow-auto p-4">
