                                  <tr>
                                      <th className="px-4 py-2 border-b">Sản phẩm</th>
                                      <th className="px-4 py-2 border-b">Shop</th>
                                      <th className="px-4 py-2 border-b text-right">Giá cũ</th>
                                      <th className="px-4 py-2 border-b text-right">Giá mới</th>
