                              </thead>
                              <tbody>
                                  {details.map((d, i) => (
                                      <tr key={i} className="border-b hover:bg-slate-50">
                                          <td className="px-4 py-3 font-medium text-slate-800">{d.productName}</td>
                                          <td className="px-4 py-3 text-slate-600">{d.shopName}</td>
