                              value={newCatName}
                              onChange={(e) => setNewCatName(e.target.value)}
                              className="flex-1 border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500"
                              placeholder="Nhập tên danh mục mới..."
                          />
                          <button 
                              onClick={() => { handleAddCategory(newCatName); setNewCatName(''); }}
                              disabled={!newCatName.trim()}
                              className="bg-indigo-600 text-white px-3 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700 disabled:opacity-50"
                          >
                              Thêm
                          </button>
                      </div>

                      <div className="border border-slate-200 rounded-lg max-h-60 overflow-y-auto">
                          {keywordCategories.map((cat, idx) => (
                              <div key={idx} className="flex justify-between items-center p-3 border-b last:border-0 hover:bg-slate-50">
                                  <span className="text-sm font-medium text-slate-700">{cat}</span>
                                  <button 
