  });
  const [bulkSelectedProductIds, setBulkSelectedProductIds] = useState<string[]>([]);
  const [bulkEditHistory, setBulkEditHistory] = useState<BulkEditHistory[]>([]);
  const [isBulkEditing, setIsBulkEditing] = useState(false);
  const [bulkEditProgress, setBulkEditProgress] = useState(0);
  const [viewingHistoryDetail, setViewingHistoryDetail] = useState<BulkEditHistory | null>(null);

  // Forbidden Keywords State
  const [keywordsList, setKeywordsList] = useState(MOCK_FORBIDDEN_KEYWORDS);
  const [keywordCategories, setKeywordCategories] = useState(['Thương hiệu/MXH', 'Khẳng định chưa kiểm chứng', 'Lừa dối người tiêu dùng', 'Phân biệt chủng tộc', 'Bạo lực và phân biệt']);
  const [selectedCategory, setSelectedCategory] = useState<string>('Thương hiệu/MXH');
  const [isKeywordModalOpen, setIsKeywordModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [keywordForm, setKeywordForm] = useState({ id: '', text: '', category: '' });

  // Flatten shops list for selection
  const allShops = INITIAL_INTEGRATIONS.flatMap(i => i.shops.map(s => ({ ...s, platform: i.platform })));

  const tabs = [
    { id: 'import', label: 'Sao chép sản phẩm', icon: Download },
    { id: 'listing', label: 'Đăng bán sản phẩm', icon: UploadCloud },
    { id: 'sync', label: 'Đồng bộ Shop chéo', icon: ArrowRightLeft },
    { id: 'bulkedit', label: 'Sửa giá hàng loạt', icon: Edit3 },
    { id: 'keywords', label: 'Từ khóa cấm', icon: ShieldBan },
  ];

  // ... (Previous Handlers for Sync, Import, Listing) ...
  const handleStartSync = () => {
    if (!syncConfig.sourceShopId) {
      alert("Vui lòng chọn Shop nguồn.");
      return;
    }
    if (syncConfig.targetShopIds.length === 0) {
      alert("Vui lòng chọn ít nhất 1 Shop đích.");
      return;
    }

    setShowSyncModal(true);
    setSyncProgress(0);

    // Simulate Sync Process
    const totalTime = 3000;
    const intervalTime = 50;
    const steps = totalTime / intervalTime;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
      setSyncProgress(progress);

      if (currentStep >= steps) {
        clearInterval(timer);

        // Add to history
        const sourceShop = allShops.find(s => s.id === syncConfig.sourceShopId);
        const newHistoryItem: SyncHistoryItem = {
            id: `h-${Date.now()}`,
            sourceShopName: sourceShop ? sourceShop.name : 'Unknown',
            targetCount: syncConfig.targetShopIds.length,
            timestamp: new Date().toLocaleString('vi-VN'),
            status: 'success',
            productsSynced: Math.floor(Math.random() * 200) + 10 // Mock number
        };
        setSyncHistory(prev => [newHistoryItem, ...prev]);
      }
    }, intervalTime);
  };

  const toggleTargetShop = (shopId: string) => {
    setSyncConfig(prev => {
      const exists = prev.targetShopIds.includes(shopId);
      return {
        ...prev,
        targetShopIds: exists 
          ? prev.targetShopIds.filter(id => id !== shopId)
          : [...prev.targetShopIds, shopId]
      };
    });
  };

  const toggleAllTargets = () => {
      const availableTargets = allShops.filter(s => s.id !== syncConfig.sourceShopId);
      const allSelected = availableTargets.length > 0 && availableTargets.every(s => syncConfig.targetShopIds.includes(s.id));

      if (allSelected) {
          setSyncConfig(prev => ({ ...prev, targetShopIds: [] }));
      } else {
          setSyncConfig(prev => ({ ...prev, targetShopIds: availableTargets.map(s => s.id) }));
      }
  };

  // --- Import Logic ---
  useEffect(() => {
      if (importConfig.sourceShopId) {
          const mockSource: SourceProduct[] = MOCK_PRODUCTS.slice(0, 15).map(p => {
              const hasSku = Math.random() > 0.2; 
              const exists = hasSku && Math.random() > 0.5; 

              return {
                  id: `src-${p.id}`,
                  name: p.name,
                  sku: hasSku ? p.sku : '', 
                  price: p.price,
                  stock: p.stock,
                  image: p.image,
                  weight: 500,
                  description: p.description,
                  status: 'active',
                  existsInOmni: exists,
                  isCopied: false
              };
          });

          mockSource.sort((a, b) => {
              const isEligibleA = !!a.sku && !a.existsInOmni && !a.isCopied;
              const isEligibleB = !!b.sku && !b.existsInOmni && !b.isCopied;

              if (isEligibleA && !isEligibleB) return -1;
              if (!isEligibleA && isEligibleB) return 1;
              return 0;
          });

          setSourceProducts(mockSource);
          setSelectedImportIds([]);
      } else {
          setSourceProducts([]);
      }
  }, [importConfig.sourceShopId]);

  const toggleImportSelection = (id: string) => {
      setSelectedImportIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const handleCopyProducts = () => {
      const count = selectedImportIds.length;
      if (count === 0) return alert("Vui lòng chọn sản phẩm để sao chép.");

      setCopiedCount(count);
      setShowProgressModal(true);
      setImportStatus('processing');
      setImportProgress(0);

      const totalTime = 2000; 
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setImportProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);
              setImportStatus('success');

              setSourceProducts(prev => prev.map(p => 
                  selectedImportIds.includes(p.id) ? { ...p, isCopied: true, existsInOmni: true } : p
              ));
              setSelectedImportIds([]); 
          }
      }, intervalTime);
  };

  // --- Bulk Edit Handlers ---
  const toggleBulkProduct = (id: string) => {
      setBulkSelectedProductIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const toggleBulkAllProducts = () => {
      if (bulkSelectedProductIds.length === MOCK_PRODUCTS.length) {
          setBulkSelectedProductIds([]);
      } else {
          setBulkSelectedProductIds(MOCK_PRODUCTS.map(p => p.id));
      }
  };

  const toggleBulkTargetShop = (shopId: string) => {
      setBulkEditConfig(prev => {
          const exists = prev.targetShopIds.includes(shopId);
          return {
              ...prev,
              targetShopIds: exists 
                  ? prev.targetShopIds.filter(id => id !== shopId) 
                  : [...prev.targetShopIds, shopId]
          };
      });
  };

  const toggleBulkAllShops = () => {
      const allIds = allShops.map(s => s.id);
      const isAllSelected = bulkEditConfig.targetShopIds.length === allIds.length;
      setBulkEditConfig(prev => ({
          ...prev,
          targetShopIds: isAllSelected ? [] : allIds
      }));
  };

  const calculateNewPrice = (currentPrice: number) => {
      const value = bulkEditConfig.type === 'percent' ? bulkEditConfig.value : parseMoney(bulkEditConfig.valueInput);

      if (!value) return currentPrice;

      let change = 0;
      if (bulkEditConfig.type === 'percent') {
          change = currentPrice * (value / 100);
      } else {
          change = value;
      }

      const newPrice = bulkEditConfig.mode === 'increase' ? currentPrice + change : currentPrice - change;
      return Math.max(0, newPrice);
  };

  const handleStartBulkEdit = () => {
      if (bulkSelectedProductIds.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
      if (bulkEditConfig.targetShopIds.length === 0) return alert("Vui lòng chọn ít nhất 1 shop để đồng bộ giá.");

      const value = bulkEditConfig.type === 'percent' ? bulkEditConfig.value : parseMoney(bulkEditConfig.valueInput);
      if (value <= 0) return alert("Vui lòng nhập giá trị điều chỉnh lớn hơn 0.");

      setIsBulkEditing(true);
      setBulkEditProgress(0);

      const totalTime = 3000;
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setBulkEditProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);

              // Generate details
              const details = bulkSelectedProductIds.map(pid => {
                  const prod = MOCK_PRODUCTS.find(p => p.id === pid);
                  const oldPrice = prod?.price || 0;
                  const newPrice = calculateNewPrice(oldPrice);
                  const randomShopId = bulkEditConfig.targetShopIds[Math.floor(Math.random() * bulkEditConfig.targetShopIds.length)];
                  const shopName = allShops.find(s => s.id === randomShopId)?.name || 'Unknown Shop';
                  return { productName: prod?.name || '', oldPrice, newPrice, shopName };
              });

              // Add to history
              const actionStr = `${bulkEditConfig.mode === 'increase' ? 'Tăng' : 'Giảm'} ${bulkEditConfig.type === 'percent' ? `${bulkEditConfig.value}%` : `${bulkEditConfig.valueInput} đ`}`;

              const historyItem: BulkEditHistory = {
                  id: `be-${Date.now()}`,
                  action: actionStr,
                  value: bulkEditConfig.type === 'percent' ? `${bulkEditConfig.value}%` : formatCurrency(parseMoney(bulkEditConfig.valueInput)),
                  shopsApplied: bulkEditConfig.targetShopIds.length,
                  productsApplied: bulkSelectedProductIds.length,
                  timestamp: new Date().toLocaleString('vi-VN'),
                  status: 'success',
                  details
              };

              setBulkEditHistory(prev => [historyItem, ...prev]);
          }
      }, intervalTime);
  };

  const handleViewHistoryDetail = (item: BulkEditHistory) => {
      setViewingHistoryDetail(item);
  };

  // --- Keyword Handlers ---
  const handleAddKeyword = () => {
    setKeywordForm({ id: '', text: '', category: selectedCategory });
    setIsKeywordModalOpen(true);
  };

  const handleEditKeyword = (kw: any) => {
    setKeywordForm(kw);
    setIsKeywordModalOpen(true);
  };

  const handleDeleteKeyword = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa từ khóa này?')) {
      setKeywordsList(prev => prev.filter(k => k.id !== id));
    }
  };

  const handleSaveKeyword = () => {
    if (!keywordForm.text || !keywordForm.category) {
      alert('Vui lòng nhập từ khóa và chọn danh mục.');
      return;
    }

    // Add new category if it doesn't exist
    if (!keywordCategories.includes(keywordForm.category)) {
        setKeywordCategories(prev => [...prev, keywordForm.category]);
    }

    setKeywordsList(prev => keywordForm.id ? prev.map(k => k.id === keywordForm.id ? keywordForm : k) : [...prev, { ...keywordForm, id: `kw-${Date.now()}` }]);
    setIsKeywordModalOpen(false);
  };

  const handleAddCategory = (newCat: string) => {
