import React, { useState, useMemo, useEffect } from 'react';
import { 
  RefreshCw, Download, ArrowRightLeft, Store, CheckSquare, Square, Edit3, 
  UploadCloud, Search, Filter, Plus, Globe, AlertCircle, CheckCircle2, 
  Clock, XCircle, ChevronRight, Image as ImageIcon, Link as LinkIcon,
  Copy, Save, ArrowLeft, Layers, Box, ShieldBan, Trash2, X, Info, AlertTriangle, Database, Rocket, Loader2, Check, Calendar, ChevronDown, Play, RotateCcw, Settings, History, TrendingUp, TrendingDown, Eye, List
} from 'lucide-react';
import { INITIAL_INTEGRATIONS, MOCK_PRODUCTS, MOCK_FORBIDDEN_KEYWORDS, MOCK_WAREHOUSES } from '../services/mockData';
import { Platform } from '../types';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const formatInputMoney = (value: string) => {
    // Remove non-digit characters
    const number = value.replace(/\D/g, '');
    // Format with dots
    return number.replace(/\B(?=(\d{3})+(?!\d))/g, '.');
};

const parseMoney = (value: string) => {
    return parseInt(value.replace(/\./g, '') || '0', 10);
};

