// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
}

// Define Interface for Sync History
interface SyncHistoryItem {
    id: string;
    sourceShopName: string;
    targetCount: number;
    timestamp: string;
    status: 'success' | 'failed' | 'partial';
    productsSynced: number;
}

// Define Bulk Edit History
interface BulkEditHistory {
    id: string;
    action: string;
    value: string;
    shopsApplied: number;
    productsApplied: number;
    timestamp: string;
    status: 'success' | 'processing';
    details?: { productName: string, oldPrice: number, newPrice: number, shopName: string }[];
}

const Tools: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'import' | 'listing' | 'sync' | 'bulkedit' | 'keywords'>('import');

  // Listing State
  const [listingFilter, setListingFilter] = useState('all');
  const [isListingModalOpen, setIsListingModalOpen] = useState(false);
  const [listingStep, setListingStep] = useState(1); // 1: Source, 2: Target, 3: Product, 4: Edit
  const [listingSource, setListingSource] = useState<'system' | 'shop' | 'link'>('system');
  const [listingSelectedShops, setListingSelectedShops] = useState<string[]>([]);
  const [listingSelectedProducts, setListingSelectedProducts] = useState<string[]>([]);

  // Listing Edit State (Existing Products)
  const [editingListing, setEditingListing] = useState<any | null>(null);
  const [showFilterPanel, setShowFilterPanel] = useState(false);

  // Listing Wizard Edit State (Step 4)
  const [listingEdits, setListingEdits] = useState<Record<string, { price: number, stock: number }>>({});

  // Publishing Progress State
  const [isPublishing, setIsPublishing] = useState(false);
  const [publishProgress, setPublishProgress] = useState(0);
  const [publishStatus, setPublishStatus] = useState<'processing' | 'success'>('processing');

  // Shop Sync State
  const [syncConfig, setSyncConfig] = useState({
    sourceShopId: '',
    targetShopIds: [] as string[],
    syncStock: true,
    syncPrice: true,
    syncInfo: false,
  });
  // New State for Sync Logic
  const [showSyncModal, setShowSyncModal] = useState(false);
  const [syncProgress, setSyncProgress] = useState(0);
  const [syncHistory, setSyncHistory] = useState<SyncHistoryItem[]>([
      { id: 'h1', sourceShopName: 'Shop Mẹ & Bé Official', targetCount: 2, timestamp: '12/05/2025 10:30', status: 'success', productsSynced: 150 },
      { id: 'h2', sourceShopName: 'Kho Sỉ Thời Trang', targetCount: 1, timestamp: '10/05/2025 14:15', status: 'partial', productsSynced: 45 }
  ]);

  // Import State (Redesigned)
  const [importConfig, setImportConfig] = useState({
      sourceShopId: '',
      targetWarehouseId: MOCK_WAREHOUSES[0].id,
      pricePolicy: 'retail' as 'retail' | 'wholesale' | 'import'
  });
  const [sourceProducts, setSourceProducts] = useState<SourceProduct[]>([]);
  const [selectedImportIds, setSelectedImportIds] = useState<string[]>([]);

  // Import Process State
  const [importProgress, setImportProgress] = useState(0);
  const [showProgressModal, setShowProgressModal] = useState(false);
  const [importStatus, setImportStatus] = useState<'processing' | 'success'>('processing');
  const [copiedCount, setCopiedCount] = useState(0);

  // Bulk Edit State
  const [bulkEditConfig, setBulkEditConfig] = useState({
      mode: 'increase' as 'increase' | 'decrease',
      type: 'percent' as 'percent' | 'amount',
      value: 0,
      valueInput: '', // String for formatting
      targetShopIds: [] as string[]
  });
  const [bulkSelectedProductIds, setBulkSelectedProductIds] = useState<string[]>([]);
  const [bulkEditHistory, setBulkEditHistory] = useState<BulkEditHistory[]>([]);
  const [isBulkEditing, setIsBulkEditing] = useState(false);
  const [bulkEditProgress, setBulkEditProgress] = useState(0);
  const [viewingHistoryDetail, setViewingHistoryDetail] = useState<BulkEditHistory | null>(null);

  // Forbidden Keywords State
  const [keywordsList, setKeywordsList] = useState(MOCK_FORBIDDEN_KEYWORDS);
  const [keywordCategories, setKeywordCategories] = useState(['Thương hiệu/MXH', 'Khẳng định chưa kiểm chứng', 'Lừa dối người tiêu dùng', 'Phân biệt chủng tộc', 'Bạo lực và phân biệt']);
  const [selectedCategory, setSelectedCategory] = useState<string>('Thương hiệu/MXH');
  const [isKeywordModalOpen, setIsKeywordModalOpen] = useState(false);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [keywordForm, setKeywordForm] = useState({ id: '', text: '', category: '' });

  // Flatten shops list for selection
  const allShops = INITIAL_INTEGRATIONS.flatMap(i => i.shops.map(s => ({ ...s, platform: i.platform })));

  const tabs = [
    { id: 'import', label: 'Sao chép sản phẩm', icon: Download },
    { id: 'listing', label: 'Đăng bán sản phẩm', icon: UploadCloud },
    { id: 'sync', label: 'Đồng bộ Shop chéo', icon: ArrowRightLeft },
    { id: 'bulkedit', label: 'Sửa giá hàng loạt', icon: Edit3 },
    { id: 'keywords', label: 'Từ khóa cấm', icon: ShieldBan },
  ];

  // ... (Previous Handlers for Sync, Import, Listing) ...
  const handleStartSync = () => {
    if (!syncConfig.sourceShopId) {
      alert("Vui lòng chọn Shop nguồn.");
      return;
    }
    if (syncConfig.targetShopIds.length === 0) {
      alert("Vui lòng chọn ít nhất 1 Shop đích.");
      return;
    }

    setShowSyncModal(true);
    setSyncProgress(0);

    // Simulate Sync Process
    const totalTime = 3000;
    const intervalTime = 50;
    const steps = totalTime / intervalTime;
    let currentStep = 0;

    const timer = setInterval(() => {
      currentStep++;
      const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
      setSyncProgress(progress);

      if (currentStep >= steps) {
        clearInterval(timer);

        // Add to history
        const sourceShop = allShops.find(s => s.id === syncConfig.sourceShopId);
        const newHistoryItem: SyncHistoryItem = {
            id: `h-${Date.now()}`,
            sourceShopName: sourceShop ? sourceShop.name : 'Unknown',
            targetCount: syncConfig.targetShopIds.length,
            timestamp: new Date().toLocaleString('vi-VN'),
            status: 'success',
            productsSynced: Math.floor(Math.random() * 200) + 10 // Mock number
        };
        setSyncHistory(prev => [newHistoryItem, ...prev]);
      }
    }, intervalTime);
  };

  const toggleTargetShop = (shopId: string) => {
    setSyncConfig(prev => {
      const exists = prev.targetShopIds.includes(shopId);
      return {
        ...prev,
        targetShopIds: exists 
          ? prev.targetShopIds.filter(id => id !== shopId)
          : [...prev.targetShopIds, shopId]
      };
    });
  };

  const toggleAllTargets = () => {
      const availableTargets = allShops.filter(s => s.id !== syncConfig.sourceShopId);
      const allSelected = availableTargets.length > 0 && availableTargets.every(s => syncConfig.targetShopIds.includes(s.id));

      if (allSelected) {
          setSyncConfig(prev => ({ ...prev, targetShopIds: [] }));
      } else {
          setSyncConfig(prev => ({ ...prev, targetShopIds: availableTargets.map(s => s.id) }));
      }
  };

  // --- Import Logic ---
  useEffect(() => {
      if (importConfig.sourceShopId) {
          const mockSource: SourceProduct[] = MOCK_PRODUCTS.slice(0, 15).map(p => {
              const hasSku = Math.random() > 0.2; 
              const exists = hasSku && Math.random() > 0.5; 

              return {
                  id: `src-${p.id}`,
                  name: p.name,
                  sku: hasSku ? p.sku : '', 
                  price: p.price,
                  stock: p.stock,
                  image: p.image,
                  weight: 500,
                  description: p.description,
                  status: 'active',
                  existsInOmni: exists,
                  isCopied: false
              };
          });

          // Sort order: Ready -> Copied -> Existing -> No SKU
          mockSource.sort((a, b) => {
              const getScore = (p: SourceProduct) => {
                  if (!p.sku) return 4;
                  if (p.existsInOmni) return 3;
                  if (p.isCopied) return 2;
                  return 1;
              };
              return getScore(a) - getScore(b);
          });

          setSourceProducts(mockSource);
          setSelectedImportIds([]);
      } else {
          setSourceProducts([]);
      }
  }, [importConfig.sourceShopId]);

  const toggleImportSelection = (id: string) => {
      setSelectedImportIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const handleCopyProducts = () => {
      const count = selectedImportIds.length;
      if (count === 0) return alert("Vui lòng chọn sản phẩm để sao chép.");

      setCopiedCount(count);
      setShowProgressModal(true);
      setImportStatus('processing');
      setImportProgress(0);

      const totalTime = 2000; 
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setImportProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);
              setImportStatus('success');

              setSourceProducts(prev => prev.map(p => 
                  selectedImportIds.includes(p.id) ? { ...p, isCopied: true, existsInOmni: true } : p
              ));
              setSelectedImportIds([]); 
          }
      }, intervalTime);
  };

  // --- Bulk Edit Handlers ---
  const toggleBulkProduct = (id: string) => {
      setBulkSelectedProductIds(prev => 
          prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]
      );
  };

  const toggleBulkAllProducts = () => {
      if (bulkSelectedProductIds.length === MOCK_PRODUCTS.length) {
          setBulkSelectedProductIds([]);
      } else {
          setBulkSelectedProductIds(MOCK_PRODUCTS.map(p => p.id));
      }
  };

  const toggleBulkTargetShop = (shopId: string) => {
      setBulkEditConfig(prev => {
          const exists = prev.targetShopIds.includes(shopId);
          return {
              ...prev,
              targetShopIds: exists 
                  ? prev.targetShopIds.filter(id => id !== shopId) 
                  : [...prev.targetShopIds, shopId]
          };
      });
  };

  const toggleBulkAllShops = () => {
      const allIds = allShops.map(s => s.id);
      const isAllSelected = bulkEditConfig.targetShopIds.length === allIds.length;
      setBulkEditConfig(prev => ({
          ...prev,
          targetShopIds: isAllSelected ? [] : allIds
      }));
  };

  const calculateNewPrice = (currentPrice: number) => {
      const value = bulkEditConfig.type === 'percent' ? bulkEditConfig.value : parseMoney(bulkEditConfig.valueInput);

      if (!value) return currentPrice;

      let change = 0;
      if (bulkEditConfig.type === 'percent') {
          change = currentPrice * (value / 100);
      } else {
          change = value;
      }

      const newPrice = bulkEditConfig.mode === 'increase' ? currentPrice + change : currentPrice - change;
      return Math.max(0, newPrice);
  };

  const handleStartBulkEdit = () => {
      if (bulkSelectedProductIds.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");
      if (bulkEditConfig.targetShopIds.length === 0) return alert("Vui lòng chọn ít nhất 1 shop để đồng bộ giá.");

      const value = bulkEditConfig.type === 'percent' ? bulkEditConfig.value : parseMoney(bulkEditConfig.valueInput);
      if (value <= 0) return alert("Vui lòng nhập giá trị điều chỉnh lớn hơn 0.");

      setIsBulkEditing(true);
      setBulkEditProgress(0);

      const totalTime = 3000;
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setBulkEditProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);

              // Generate details
              const details = bulkSelectedProductIds.map(pid => {
                  const prod = MOCK_PRODUCTS.find(p => p.id === pid);
                  const oldPrice = prod?.price || 0;
                  const newPrice = calculateNewPrice(oldPrice);
                  const randomShopId = bulkEditConfig.targetShopIds[Math.floor(Math.random() * bulkEditConfig.targetShopIds.length)];
                  const shopName = allShops.find(s => s.id === randomShopId)?.name || 'Unknown Shop';
                  return { productName: prod?.name || '', oldPrice, newPrice, shopName };
              });

              // Add to history
              const actionStr = `${bulkEditConfig.mode === 'increase' ? 'Tăng' : 'Giảm'} ${bulkEditConfig.type === 'percent' ? `${bulkEditConfig.value}%` : `${bulkEditConfig.valueInput} đ`}`;

              const historyItem: BulkEditHistory = {
                  id: `be-${Date.now()}`,
                  action: actionStr,
                  value: bulkEditConfig.type === 'percent' ? `${bulkEditConfig.value}%` : formatCurrency(parseMoney(bulkEditConfig.valueInput)),
                  shopsApplied: bulkEditConfig.targetShopIds.length,
                  productsApplied: bulkSelectedProductIds.length,
                  timestamp: new Date().toLocaleString('vi-VN'),
                  status: 'success',
                  details
              };

              setBulkEditHistory(prev => [historyItem, ...prev]);
          }
      }, intervalTime);
  };

  const handleViewHistoryDetail = (item: BulkEditHistory) => {
      setViewingHistoryDetail(item);
  };

  // --- Keyword Handlers ---
  const handleAddKeyword = () => {
    setKeywordForm({ id: '', text: '', category: selectedCategory });
    setIsKeywordModalOpen(true);
  };

  const handleEditKeyword = (kw: any) => {
    setKeywordForm(kw);
    setIsKeywordModalOpen(true);
  };

  const handleDeleteKeyword = (id: string) => {
    if (confirm('Bạn có chắc chắn muốn xóa từ khóa này?')) {
      setKeywordsList(prev => prev.filter(k => k.id !== id));
    }
  };

  const handleSaveKeyword = () => {
    if (!keywordForm.text || !keywordForm.category) {
      alert('Vui lòng nhập từ khóa và chọn danh mục.');
      return;
    }

    // Add new category if it doesn't exist
    if (!keywordCategories.includes(keywordForm.category)) {
        setKeywordCategories(prev => [...prev, keywordForm.category]);
    }

    setKeywordsList(prev => keywordForm.id ? prev.map(k => k.id === keywordForm.id ? keywordForm : k) : [...prev, { ...keywordForm, id: `kw-${Date.now()}` }]);
    setIsKeywordModalOpen(false);
  };

  const handleAddCategory = (newCat: string) => {
      if (newCat && !keywordCategories.includes(newCat)) {
          setKeywordCategories([...keywordCategories, newCat]);
      }
  };

  const handleDeleteCategory = (cat: string) => {
      if (confirm(`Bạn có chắc chắn muốn xóa danh mục "${cat}"? Các từ khóa trong danh mục này cũng sẽ bị xóa.`)) {
          setKeywordCategories(prev => prev.filter(c => c !== cat));
          setKeywordsList(prev => prev.filter(k => k.category !== cat));
          if (selectedCategory === cat) setSelectedCategory(keywordCategories[0] || '');
      }
  };

  // --- Listing Wizard Handlers (Restored) ---
  const toggleListingShop = (shopId: string) => {
    setListingSelectedShops(prev => 
      prev.includes(shopId) ? prev.filter(id => id !== shopId) : [...prev, shopId]
    );
  };

  const toggleListingProduct = (productId: string) => {
    setListingSelectedProducts(prev => 
      prev.includes(productId) ? prev.filter(id => id !== productId) : [...prev, productId]
    );
  };

  const resetListingWizard = () => {
    setIsListingModalOpen(false);
    setListingStep(1);
    setListingSelectedShops([]);
    setListingSelectedProducts([]);
    setListingEdits({});
  };

  const handleListingEditChange = (id: string, field: 'price' | 'stock', value: string) => {
      let numValue = 0;
      if (field === 'price') {
          numValue = parseInt(value.replace(/\./g, '') || '0', 10);
      } else {
          numValue = parseInt(value || '0', 10);
      }

      setListingEdits(prev => ({
          ...prev,
          [id]: { 
              ...prev[id], 
              [field]: numValue 
          }
      }));
  };

  const handlePublishListing = () => {
      if (listingSelectedProducts.length === 0) return alert("Vui lòng chọn ít nhất 1 sản phẩm.");

      setIsPublishing(true);
      setPublishProgress(0);
      setPublishStatus('processing');

      const totalTime = 3000;
      const intervalTime = 50;
      const steps = totalTime / intervalTime;
      let currentStep = 0;

      const timer = setInterval(() => {
          currentStep++;
          const progress = Math.min(Math.round((currentStep / steps) * 100), 100);
          setPublishProgress(progress);

          if (currentStep >= steps) {
              clearInterval(timer);
              setPublishStatus('success');
          }
      }, intervalTime);
  };

  const renderListingWizard = () => {
    if (!isListingModalOpen) return null;

    return (
      <div className="fixed inset-0 bg-black/60 z-[90] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl overflow-hidden flex flex-col h-[90vh]">
          {/* Header */}
          <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
            <div>
              <h3 className="font-bold text-lg text-slate-800">Đăng bán sản phẩm đa sàn</h3>
              <div className="flex gap-2 mt-1">
                {[1, 2, 3, 4].map(s => (
                  <div key={s} className={`h-1.5 w-8 rounded-full ${s <= listingStep ? 'bg-indigo-600' : 'bg-slate-200'}`}></div>
                ))}
              </div>
            </div>
            <button onClick={resetListingWizard}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
          </div>

          {/* Body */}
          <div className="flex-1 overflow-y-auto p-6">

            {/* Step 1: Source */}
            {listingStep === 1 && (
              <div className="space-y-6">
                <h4 className="text-lg font-bold text-slate-700 text-center">Bước 1: Chọn nguồn sản phẩm</h4>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div 
                    onClick={() => setListingSource('system')}
                    className={`p-6 border-2 rounded-xl cursor-pointer hover:bg-slate-50 flex flex-col items-center gap-3 transition-all ${listingSource === 'system' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200'}`}
                  >
                    <Database size={32} className={listingSource === 'system' ? "text-indigo-600" : "text-slate-400"} />
                    <span className="font-bold text-slate-700">Từ Hệ thống (OmniSales)</span>
                    <p className="text-xs text-slate-500 text-center">Lấy sản phẩm đã có trong kho tổng</p>
                  </div>
                  <div 
                    onClick={() => setListingSource('shop')}
                    className={`p-6 border-2 rounded-xl cursor-pointer hover:bg-slate-50 flex flex-col items-center gap-3 transition-all ${listingSource === 'shop' ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200'}`}
                  >
                    <Store size={32} className={listingSource === 'shop' ? "text-indigo-600" : "text-slate-400"} />
                    <span className="font-bold text-slate-700">Từ Shop khác</span>
