// Define Interface for Source Product in Import Tool
interface SourceProduct {
    id: string;
    name: string;
    sku: string;
    price: number;
    stock: number;
    image: string;
    weight: number;
    description: string;
    status: 'active' | 'inactive';
    existsInOmni: boolean; // Is SKU already in OmniSales?
    isCopied: boolean; // Has been copied in this session?
}

// Define Interface for Sync History
interface SyncHistoryItem {
    id: string;
    sourceShopName: string;
    targetCount: number;
    timestamp: string;
    status: 'success' | 'failed' | 'partial';
    productsSynced: number;
}

// Define Bulk Edit History
interface BulkEditHistory {
    id: string;
    action: string;
    value: string;
    shopsApplied: number;
    productsApplied: number;
    timestamp: string;
    status: 'success' | 'processing';
    details?: { productName: string, oldPrice: number, newPrice: number, shopName: string }[];
}

