                    <p className="text-xs text-slate-500 text-center">Dán link Shopee/Lazada/TikTok</p>
                  </div>
                </div>

                {listingSource === 'link' && (
                  <div className="mt-4">
                    <label className="block text-sm font-bold text-slate-700 mb-2">Dán đường dẫn sản phẩm</label>
                    <input type="text" className="w-full border border-slate-300 rounded-lg px-4 py-2" placeholder="https://shopee.vn/product/..." />
                  </div>
                )}
              </div>
            )}

            {/* Step 2: Target */}
            {listingStep === 2 && (
              <div className="space-y-6">
                <h4 className="text-lg font-bold text-slate-700 text-center">Bước 2: Chọn nơi đăng bán</h4>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {allShops.map(shop => (
                    <div 
