                      className={`p-4 border-2 rounded-xl cursor-pointer hover:bg-slate-50 flex items-center gap-3 transition-all ${listingSelectedShops.includes(shop.id) ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200'}`}
