                      </div>
                      {LOGOS[shop.platform] && <img src={LOGOS[shop.platform]} className="w-6 h-6 object-contain" />}
                      <div>
                        <div className="font-bold text-sm text-slate-700">{shop.name}</div>
                        <div className="text-xs text-slate-500">{shop.platform}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Step 3: Product Select */}
            {listingStep === 3 && (
              <div className="space-y-4">
                <h4 className="text-lg font-bold text-slate-700 text-center">Bước 3: Chọn sản phẩm</h4>
