                        <th className="px-4 py-3 w-32 text-center">Kho đăng bán</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {listingSelectedProducts.map(pid => {
                        const p = MOCK_PRODUCTS.find(prod => prod.id === pid);
                        if (!p) return null;
                        const edited = listingEdits[pid] || { price: p.price, stock: p.stock };

                        return (
                          <tr key={p.id} className="hover:bg-slate-50">
                            <td className="px-4 py-3 flex items-center gap-3">
                              <img src={p.image} className="w-10 h-10 rounded border border-slate-200 object-cover" />
                              <span className="font-medium text-slate-700 line-clamp-1">{p.name}</span>
                            </td>
                            <td className="px-4 py-3 text-right">
                              <input 
                                type="text" 
                                value={formatInputMoney(String(edited.price))}
                                onChange={(e) => handleListingEditChange(pid, 'price', e.target.value)}
                                className="w-full border border-slate-300 rounded px-2 py-1 text-right font-bold text-indigo-600"
                              />
                            </td>
                            <td className="px-4 py-3 text-center">
                              <input 
                                type="number" 
                                value={edited.stock}
                                onChange={(e) => handleListingEditChange(pid, 'stock', e.target.value)}
                                className="w-full border border-slate-300 rounded px-2 py-1 text-center font-bold"
                              />
                            </td>
                          </tr>
