                        <th className="px-4 py-3 text-center">Tồn kho</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {MOCK_PRODUCTS.slice(0, 10).map(p => (
                        <tr key={p.id} className={`hover:bg-slate-50 ${listingSelectedProducts.includes(p.id) ? 'bg-indigo-50' : ''}`} onClick={() => toggleListingProduct(p.id)}>
                          <td className="px-4 py-3 text-center">
                            <input type="checkbox" checked={listingSelectedProducts.includes(p.id)} readOnly className="rounded text-indigo-600 focus:ring-indigo-500 pointer-events-none" />
                          </td>
                          <td className="px-4 py-3 flex items-center gap-3">
                            <img src={p.image} className="w-10 h-10 rounded border border-slate-200 object-cover" />
                            <span className="font-medium text-slate-700 line-clamp-1">{p.name}</span>
                          </td>
                          <td className="px-4 py-3 text-right">{formatCurrency(p.price)}</td>
                          <td className="px-4 py-3 text-center">{p.stock}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
