            {/* Step 4: Confirm & Edit */}
            {listingStep === 4 && (
              <div className="space-y-4">
                <h4 className="text-lg font-bold text-slate-700 text-center">Bước 4: Chỉnh sửa thông tin đăng bán</h4>
