                            <button onClick={() => handleEditKeyword(kw)} className="text-slate-400 hover:text-indigo-600"><Edit3 size={14}/></button>
                            <button onClick={() => handleDeleteKeyword(kw.id)} className="text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
