                   <button onClick={() => setIsKeywordModalOpen(false)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
                </div>
                <div className="p-6 space-y-4">
                   <div>
                      <label className="block text-sm font-medium text-slate-700 mb-1">Từ khóa <span className="text-red-500">*</span></label>
                      <input 
                        type="text" 
