                   </div>
                </div>
                <div className="p-4 border-t border-slate-100 flex justify-end gap-2 bg-slate-50">
                   <button onClick={() => setIsKeywordModalOpen(false)} className="px-4 py-2 border border-slate-200 bg-white rounded-lg text-slate-600 hover:bg-slate-100 text-sm font-medium">Hủy</button>
