                              <svg className="animate-spin w-full h-full text-blue-100" viewBox="0 0 24 24">
                                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
                                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                              </svg>
                              <div className="absolute inset-0 flex items-center justify-center text-sm font-bold text-blue-600">
                                  {publishProgress}%
                              </div>
                          </div>
                          <h3 className="text-xl font-bold text-slate-800 mb-2">Đang đăng bán...</h3>
