                  <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                      <div>
                          <h3 className="font-bold text-lg text-slate-800">Chi tiết thay đổi giá</h3>
                          <p className="text-xs text-slate-500">{viewingHistoryDetail.timestamp} • {viewingHistoryDetail.action}</p>
                      </div>
                      <button onClick={() => setViewingHistoryDetail(null)}><X size={20} className="text-slate-400 hover:text-slate-600"/></button>
