                      <table className="w-full text-sm text-left">
                          <thead className="bg-white text-slate-500 font-semibold border-b border-slate-200 sticky top-0 shadow-sm">
                              <tr>
                                  <th className="px-6 py-3">Sản phẩm</th>
                                  <th className="px-6 py-3">Shop áp dụng</th>
                                  <th className="px-6 py-3 text-right">Giá cũ</th>
                                  <th className="px-6 py-3 text-right">Giá mới</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100">
                              {viewingHistoryDetail.details?.map((d, idx) => (
                                  <tr key={idx} className="hover:bg-slate-50">
